import { Link, useLocation } from "react-router-dom";
import { Link2, Radio } from "lucide-react";
import { cn } from "@/lib/utils";

export function BrandMark({
  className,
  compact = false,
  linkTo,
}: {
  className?: string;
  compact?: boolean;
  linkTo?: string | null;
}) {
  const location = useLocation();
  const href = linkTo === undefined ? "/projects" : linkTo;
  const inner = (
    <>
      <div
        className={cn(
          "relative flex shrink-0 items-center justify-center rounded-lg bg-primary/15 ring-1 ring-primary/25",
          compact ? "h-8 w-8" : "h-10 w-10",
        )}
      >
        <Link2 className={cn("text-primary", compact ? "h-4 w-4" : "h-5 w-5")} />
        <Radio
          className={cn(
            "absolute rounded-full bg-card p-0.5 text-primary",
            compact ? "-bottom-0.5 -right-0.5 h-3 w-3" : "-bottom-1 -right-1 h-4 w-4",
          )}
        />
      </div>
      <div className="min-w-0">
        <p className={cn("font-semibold tracking-tight", compact ? "text-sm" : "text-base")}>Task Bridge</p>
        {compact ? <p className="text-[10px] text-muted-foreground">v0.1</p> : null}
      </div>
    </>
  );

  if (!href) {
    return <div className={cn("flex items-center gap-2.5", className)}>{inner}</div>;
  }

  return (
    <Link
      to={href}
      state={location.pathname.startsWith("/projects/") ? { from: location.pathname } : undefined}
      className={cn(
        "flex items-center gap-2.5 rounded-lg transition-colors hover:bg-white/[0.04]",
        compact ? "-mx-1 px-1 py-0.5" : "px-1 py-0.5",
        className,
      )}
    >
      {inner}
    </Link>
  );
}

import { createContext, useCallback, useContext, useRef, useState } from "react";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";

type ConfirmOptions = {
  title?: string;
  message: string;
  confirmLabel?: string;
  cancelLabel?: string;
};

type ConfirmContextValue = {
  confirmDestructive: (message: string, options?: Omit<ConfirmOptions, "message">) => Promise<boolean>;
};

const ConfirmContext = createContext<ConfirmContextValue | null>(null);

export function ConfirmDialogProvider({ children }: { children: React.ReactNode }) {
  const [open, setOpen] = useState(false);
  const [options, setOptions] = useState<ConfirmOptions>({ message: "" });
  const resolveRef = useRef<((value: boolean) => void) | null>(null);

  const confirmDestructive = useCallback(
    (message: string, extra?: Omit<ConfirmOptions, "message">) => {
      return new Promise<boolean>((resolve) => {
        resolveRef.current = resolve;
        setOptions({ message, ...extra });
        setOpen(true);
      });
    },
    [],
  );

  function finish(result: boolean) {
    setOpen(false);
    resolveRef.current?.(result);
    resolveRef.current = null;
  }

  return (
    <ConfirmContext.Provider value={{ confirmDestructive }}>
      {children}
      <Dialog
        open={open}
        onOpenChange={(next) => {
          if (!next) finish(false);
        }}
      >
        <DialogContent className="max-w-md border-white/[0.1] bg-[#111] sm:rounded-xl [&>button]:hidden">
          <DialogHeader>
            <DialogTitle>{options.title ?? "Delete?"}</DialogTitle>
            <DialogDescription>{options.message}</DialogDescription>
          </DialogHeader>
          <DialogFooter className="gap-2 sm:gap-2">
            <Button type="button" variant="outline" onClick={() => finish(false)}>
              {options.cancelLabel ?? "Cancel"}
            </Button>
            <Button type="button" variant="destructive" onClick={() => finish(true)}>
              {options.confirmLabel ?? "Delete"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </ConfirmContext.Provider>
  );
}

export function useConfirm() {
  const context = useContext(ConfirmContext);
  if (!context) {
    throw new Error("useConfirm must be used within ConfirmDialogProvider");
  }
  return context;
}

import { Loader2, Plus } from "lucide-react";
import { useEffect, useState } from "react";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import type { Session } from "@/lib/session";
import { createProject, DEFAULT_WORKFLOW_TEMPLATE_ID, fetchWorkflowTemplates, type Project, type WorkflowTemplateSummary } from "@/lib/api";
import { cn } from "@/lib/utils";

type CreateProjectPanelProps = {
  session: Session;
  onCreated: (project: Project) => void;
  onCancel: () => void;
};

export function CreateProjectPanel({ session, onCreated, onCancel }: CreateProjectPanelProps) {
  const [creating, setCreating] = useState(false);
  const [name, setName] = useState("");
  const [repoPath, setRepoPath] = useState("");
  const [description, setDescription] = useState("");
  const [templates, setTemplates] = useState<WorkflowTemplateSummary[]>([]);
  const [workflowTemplateId, setWorkflowTemplateId] = useState("");

  useEffect(() => {
    void fetchWorkflowTemplates(session)
      .then((items) => {
        setTemplates(items);
        setWorkflowTemplateId((current) => {
          if (items.some((item) => item.id === current)) return current;
          const empty = items.find((item) => item.id === DEFAULT_WORKFLOW_TEMPLATE_ID);
          return empty?.id ?? items[0]?.id ?? DEFAULT_WORKFLOW_TEMPLATE_ID;
        });
      })
      .catch(() => setTemplates([]));
  }, [session]);

  async function handleCreate() {
    const trimmedName = name.trim();
    const trimmedRepo = repoPath.trim();
    if (!trimmedName || !trimmedRepo) return;

    setCreating(true);
    try {
      const created = await createProject(session, {
        name: trimmedName,
        id: "",
        repoPath: trimmedRepo,
        description: description.trim(),
        workflowTemplateId: workflowTemplateId.trim() || DEFAULT_WORKFLOW_TEMPLATE_ID,
      });
      onCreated(created);
    } catch (err) {
      toast.error(err instanceof Error ? err.message : "Failed to create project");
    } finally {
      setCreating(false);
    }
  }

  const canSubmit = Boolean(name.trim() && repoPath.trim());

  return (
    <div className="mx-auto w-full max-w-lg space-y-8">
      <div>
        <h1 className="text-2xl font-semibold tracking-tight text-white">New project</h1>
        <p className="mt-2 text-sm text-muted-foreground">
          Choose a workspace path and starting workflow template.
        </p>
      </div>

      <div className="panel-card space-y-5 p-6">
        <div className="space-y-2">
          <Label htmlFor="project-name">Name</Label>
          <Input
            id="project-name"
            value={name}
            onChange={(event) => setName(event.target.value)}
            placeholder="My App"
            disabled={creating}
            autoFocus
          />
        </div>
        <div className="space-y-2">
          <Label htmlFor="project-repo">Repo path</Label>
          <Input
            id="project-repo"
            value={repoPath}
            onChange={(event) => setRepoPath(event.target.value)}
            placeholder="C:\dev\my-app"
            disabled={creating}
          />
        </div>
        <div className="space-y-2">
          <Label htmlFor="project-description">Description</Label>
          <Textarea
            id="project-description"
            value={description}
            onChange={(event) => setDescription(event.target.value)}
            placeholder="Optional notes about this project"
            rows={3}
            disabled={creating}
          />
        </div>
        {templates.length > 0 && (
          <div className="space-y-2">
            <Label>Workflow template</Label>
            <div className="grid gap-2">
              {templates.map((template) => (
                <button
                  key={template.id}
                  type="button"
                  disabled={creating}
                  onClick={() => setWorkflowTemplateId(template.id)}
                  className={cn(
                    "rounded-xl border px-4 py-3 text-left transition-colors",
                    workflowTemplateId === template.id
                      ? "border-primary bg-primary/10"
                      : "border-white/[0.08] hover:border-white/[0.14]",
                  )}
                >
                  <p className="text-sm font-medium text-white">{template.title}</p>
                  <p className="mt-0.5 text-xs text-muted-foreground">{template.description}</p>
                </button>
              ))}
            </div>
          </div>
        )}
        <div className="flex justify-end gap-2 pt-2">
          <Button variant="outline" onClick={onCancel} disabled={creating}>
            Cancel
          </Button>
          <Button disabled={creating || !canSubmit} onClick={() => void handleCreate()}>
            {creating ? <Loader2 className="h-4 w-4 animate-spin" /> : <Plus className="h-4 w-4" />}
            Create
          </Button>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState } from "react";
import { Loader2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";

type CreateTaskModalProps = {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  targetLabel: string | null;
  saving?: boolean;
  onCreate: (title: string, description: string) => void;
};

export function CreateTaskModal({
  open,
  onOpenChange,
  targetLabel,
  saving = false,
  onCreate,
}: CreateTaskModalProps) {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");

  useEffect(() => {
    if (open) {
      setTitle("");
      setDescription("");
    }
  }, [open]);

  const canCreate = title.trim().length > 0 && !saving;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-lg gap-0 overflow-hidden p-0 sm:rounded-xl">
        <DialogHeader className="border-b border-white/[0.06] px-6 py-4">
          <DialogTitle>New task</DialogTitle>
          <p className="text-xs text-muted-foreground">
            Adding to{" "}
            <span className="font-medium text-foreground">{targetLabel ?? "this epic"}</span>
          </p>
        </DialogHeader>

        <div className="space-y-4 px-6 py-5">
          <div className="space-y-1.5">
            <label className="text-xs font-medium text-muted-foreground">Title</label>
            <Input
              value={title}
              onChange={(event) => setTitle(event.target.value)}
              placeholder="Task title"
              disabled={saving}
              autoFocus
              onKeyDown={(event) => {
                if (event.key === "Enter" && !event.shiftKey && canCreate) {
                  event.preventDefault();
                  onCreate(title.trim(), description.trim());
                }
              }}
            />
          </div>
          <div className="space-y-1.5">
            <label className="text-xs font-medium text-muted-foreground">Description</label>
            <Textarea
              value={description}
              onChange={(event) => setDescription(event.target.value)}
              placeholder="What needs to happen? (optional)"
              rows={5}
              disabled={saving}
              className="resize-y rounded-xl border-white/[0.1] bg-[#111111]"
            />
          </div>
        </div>

        <DialogFooter className="border-t border-white/[0.06] px-6 py-4">
          <Button type="button" variant="outline" disabled={saving} onClick={() => onOpenChange(false)}>
            Cancel
          </Button>
          <Button
            type="button"
            disabled={!canCreate}
            onClick={() => onCreate(title.trim(), description.trim())}
          >
            {saving ? <Loader2 className="h-4 w-4 animate-spin" /> : null}
            Create task
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { useState } from "react";
import { MarkdownView } from "@/components/MarkdownView";
import { cn } from "@/lib/utils";

type DescriptionEditorProps = {
  value: string;
  onChange: (value: string) => void;
  placeholder?: string;
  minRows?: number;
  className?: string;
};

export function DescriptionEditor({
  value,
  onChange,
  placeholder = "Write in markdownΓÇª",
  minRows = 10,
  className,
}: DescriptionEditorProps) {
  const [mode, setMode] = useState<"write" | "preview">("write");
  const trimmed = value.trim();

  return (
    <div className={cn("overflow-hidden rounded-lg border border-white/[0.08] bg-[#0f0f0f]", className)}>
      <div className="flex items-center justify-between border-b border-white/[0.06] px-2 py-1.5">
        <div className="flex gap-0.5">
          <TabButton active={mode === "write"} onClick={() => setMode("write")}>
            Write
          </TabButton>
          <TabButton active={mode === "preview"} onClick={() => setMode("preview")}>
            Preview
          </TabButton>
        </div>
        <span className="text-[10px] text-muted-foreground">Markdown</span>
      </div>
      {mode === "write" ? (
        <textarea
          value={value}
          onChange={(event) => onChange(event.target.value)}
          placeholder={placeholder}
          rows={minRows}
          className="w-full resize-y border-0 bg-transparent px-3 py-2.5 text-sm leading-relaxed text-foreground outline-none placeholder:text-muted-foreground/60"
        />
      ) : (
        <div className="min-h-[8rem] px-3 py-2.5">
          {trimmed ? (
            <MarkdownView content={value} />
          ) : (
            <p className="text-sm italic text-muted-foreground">Nothing to preview yet.</p>
          )}
        </div>
      )}
    </div>
  );
}

function TabButton({
  active,
  onClick,
  children,
}: {
  active: boolean;
  onClick: () => void;
  children: React.ReactNode;
}) {
  return (
    <button
      type="button"
      onClick={onClick}
      className={cn(
        "rounded-md px-2.5 py-1 text-[11px] font-medium transition-colors",
        active
          ? "bg-white/[0.08] text-foreground"
          : "text-muted-foreground hover:bg-white/[0.04] hover:text-foreground",
      )}
    >
      {children}
    </button>
  );
}

import { useEffect, useState } from "react";
import { DescriptionEditor } from "@/components/DescriptionEditor";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";

type DescriptionEditorModalProps = {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  title: string;
  value: string;
  onSave: (value: string) => void;
  placeholder?: string;
  saving?: boolean;
};

export function DescriptionEditorModal({
  open,
  onOpenChange,
  title,
  value,
  onSave,
  placeholder,
  saving = false,
}: DescriptionEditorModalProps) {
  const [draft, setDraft] = useState(value);

  useEffect(() => {
    if (open) setDraft(value);
  }, [open, value]);

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-h-[90vh] max-w-3xl gap-0 overflow-hidden p-0 sm:rounded-xl">
        <DialogHeader className="border-b border-white/[0.06] px-6 py-4">
          <DialogTitle>{title}</DialogTitle>
        </DialogHeader>
        <div className="max-h-[calc(90vh-8rem)] overflow-y-auto px-6 py-4">
          <DescriptionEditor
            value={draft}
            onChange={setDraft}
            placeholder={placeholder}
            minRows={18}
            className="min-h-[20rem]"
          />
        </div>
        <DialogFooter className="border-t border-white/[0.06] px-6 py-4">
          <Button type="button" variant="outline" disabled={saving} onClick={() => onOpenChange(false)}>
            Cancel
          </Button>
          <Button
            type="button"
            disabled={saving}
            onClick={() => {
              onSave(draft);
            }}
          >
            {saving ? "SavingΓÇª" : "Save"}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { Loader2 } from "lucide-react";
import { useEffect, useState } from "react";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select } from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import {
  fetchWorkflowTemplates,
  updateProject,
  type Project,
  type WorkflowTemplateSummary,
} from "@/lib/api";
import type { Session } from "@/lib/session";

type EditProjectModalProps = {
  session: Session;
  project: Project | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSaved: (project: Project) => void;
};

export function EditProjectModal({
  session,
  project,
  open,
  onOpenChange,
  onSaved,
}: EditProjectModalProps) {
  const [saving, setSaving] = useState(false);
  const [name, setName] = useState("");
  const [repoPath, setRepoPath] = useState("");
  const [description, setDescription] = useState("");
  const [workflowTemplateId, setWorkflowTemplateId] = useState("");
  const [templates, setTemplates] = useState<WorkflowTemplateSummary[]>([]);

  useEffect(() => {
    if (!open || !project) return;
    setName(project.name);
    setRepoPath(project.repoPath.trim());
    setDescription(project.description.trim());
    setWorkflowTemplateId("");
    void fetchWorkflowTemplates(session)
      .then(setTemplates)
      .catch(() => setTemplates([]));
  }, [open, project, session]);

  async function handleSave() {
    if (!project) return;
    const trimmedName = name.trim();
    const trimmedRepo = repoPath.trim();
    if (!trimmedName || !trimmedRepo) {
      toast.error("Name and folder path are required");
      return;
    }

    const currentTemplateId = project.workflowTemplateId.trim();
    const selectedTemplateId = workflowTemplateId.trim();
    const nextTemplateId = selectedTemplateId !== "" ? selectedTemplateId : currentTemplateId;

    setSaving(true);
    try {
      const updated = await updateProject(session, project.id, {
        name: trimmedName,
        repoPath: trimmedRepo,
        description: description.trim(),
        workflowTemplateId: nextTemplateId,
      });
      onSaved(updated);
      onOpenChange(false);
      toast.success("Project updated");
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to update project");
    } finally {
      setSaving(false);
    }
  }

  const canSubmit = Boolean(name.trim() && repoPath.trim());

  const currentTemplate = templates.find((item) => item.id === project?.workflowTemplateId);
  const selectedTemplateId = workflowTemplateId.trim();
  const pipelineWillChange =
    selectedTemplateId !== "" &&
    selectedTemplateId !== project?.workflowTemplateId.trim();
  const selectedTemplate = templates.find((item) => item.id === selectedTemplateId);

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-lg gap-0 overflow-hidden p-0 sm:rounded-xl">
        <DialogHeader className="border-b border-white/[0.06] px-6 py-4">
          <DialogTitle>Edit project</DialogTitle>
          {project ? (
            <p className="text-xs text-muted-foreground">{project.id}</p>
          ) : null}
        </DialogHeader>

        <div className="space-y-4 px-6 py-5">
          <div className="space-y-2">
            <Label htmlFor="edit-project-name">Name</Label>
            <Input
              id="edit-project-name"
              value={name}
              onChange={(event) => setName(event.target.value)}
              disabled={saving}
            />
          </div>
          <div className="space-y-2">
            <Label htmlFor="edit-project-repo">Folder path</Label>
            <Input
              id="edit-project-repo"
              value={repoPath}
              onChange={(event) => setRepoPath(event.target.value)}
              disabled={saving}
            />
          </div>
          <div className="space-y-2">
            <Label htmlFor="edit-project-description">Description</Label>
            <Textarea
              id="edit-project-description"
              value={description}
              onChange={(event) => setDescription(event.target.value)}
              rows={3}
              disabled={saving}
            />
          </div>
          {templates.length > 0 ? (
            <div className="space-y-2">
              <Label htmlFor="edit-project-workflow">Pipeline template</Label>
              {currentTemplate ? (
                <p className="text-xs text-muted-foreground">
                  Current: {currentTemplate.title}
                </p>
              ) : project?.workflowTemplateId ? (
                <p className="text-xs text-muted-foreground">
                  Current: {project.workflowTemplateId}
                </p>
              ) : null}
              <Select
                id="edit-project-workflow"
                value={workflowTemplateId}
                onChange={(event) => setWorkflowTemplateId(event.target.value)}
                disabled={saving}
              >
                <option value="">Keep current pipeline</option>
                {templates.map((template) => (
                  <option key={template.id} value={template.id}>
                    {template.title}
                  </option>
                ))}
              </Select>
              {pipelineWillChange ? (
                <p className="text-xs text-amber-400/90">
                  Switching to {selectedTemplate?.title ?? selectedTemplateId} resets existing epic
                  workflows and removes their spawned subtasks.
                </p>
              ) : null}
            </div>
          ) : null}
        </div>

        <DialogFooter className="border-t border-white/[0.06] px-6 py-4">
          <Button variant="outline" onClick={() => onOpenChange(false)} disabled={saving}>
            Cancel
          </Button>
          <Button disabled={saving || !canSubmit} onClick={() => void handleSave()}>
            {saving ? <Loader2 className="h-4 w-4 animate-spin" /> : null}
            Save
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { useLayoutEffect, useRef, useState } from "react";
import { MarkdownView } from "@/components/MarkdownView";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

type ExpandableMarkdownProps = {
  content: string;
  collapsedMaxHeight?: number;
  className?: string;
};

export function ExpandableMarkdown({
  content,
  collapsedMaxHeight = 168,
  className,
}: ExpandableMarkdownProps) {
  const [expanded, setExpanded] = useState(false);
  const [canExpand, setCanExpand] = useState(false);
  const bodyRef = useRef<HTMLDivElement>(null);

  useLayoutEffect(() => {
    const node = bodyRef.current;
    if (!node) return;
    setCanExpand(node.scrollHeight > collapsedMaxHeight + 1);
  }, [content, collapsedMaxHeight]);

  return (
    <div className={className}>
      <div
        ref={bodyRef}
        className={cn(!expanded && canExpand && "overflow-hidden")}
        style={!expanded && canExpand ? { maxHeight: collapsedMaxHeight } : undefined}
      >
        <MarkdownView content={content} />
      </div>
      {canExpand ? (
        <Button
          type="button"
          variant="link"
          className="mt-1 h-auto px-0 text-sm"
          onClick={() => setExpanded((value) => !value)}
        >
          {expanded ? "Show less" : "Show more"}
        </Button>
      ) : null}
    </div>
  );
}

import { Loader2 } from "lucide-react";
import { Button } from "@/components/ui/button";

export function LoadMore({
  loaded,
  hasMore,
  loading,
  onLoadMore,
}: {
  loaded: number;
  hasMore: boolean;
  loading?: boolean;
  onLoadMore: () => void;
}) {
  if (loaded === 0 && !hasMore) return null;

  return (
    <div className="flex flex-col items-center gap-2 pt-2">
      <p className="text-xs text-muted-foreground">{loaded} loaded</p>
      {hasMore ? (
        <Button variant="outline" size="sm" disabled={loading} onClick={onLoadMore}>
          {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : null}
          Load more
        </Button>
      ) : loaded > 0 ? (
        <p className="text-xs text-muted-foreground">End of list</p>
      ) : null}
    </div>
  );
}

import { useMemo } from "react";
import { marked } from "marked";
import { cn } from "@/lib/utils";

marked.setOptions({
  gfm: true,
  breaks: true,
});

type MarkdownViewProps = {
  content: string | null | undefined;
  className?: string;
  variant?: "default" | "comment";
};

export function MarkdownView({ content, className, variant = "default" }: MarkdownViewProps) {
  const html = useMemo(() => {
    if (!content?.trim()) return "";
