import type { StageTaskTemplate } from "@/lib/api";

export const NODE_ADD_BTN_SIZE = 28;

function createTaskTemplate(stageTitle: string, index: number): StageTaskTemplate {
  return {
    id: `task-${crypto.randomUUID()}`,
    title: index === 0 ? "New task" : `${stageTitle} task ${index + 1}`,
    description: "",
    dependsOn: [],
    children: [],
  };
}

export function sanitizeTaskNode(node: StageTaskTemplate): StageTaskTemplate {
  const children = (node.children ?? []).map(sanitizeTaskNode);
  return {
    id: node.id,
    title: node.title,
    description: node.description ?? "",
    assigneeRole: node.assigneeRole ?? null,
    dependsOn: node.dependsOn ?? [],
    children,
  };
}

export function sanitizeStageTemplates(nodes: StageTaskTemplate[]): StageTaskTemplate[] {
  return nodes.map(sanitizeTaskNode);
}

export function flattenTemplates(nodes: StageTaskTemplate[]): StageTaskTemplate[] {
  const result: StageTaskTemplate[] = [];
  for (const node of sanitizeStageTemplates(nodes)) {
    result.push(node);
    if (node.children.length > 0) {
      result.push(...flattenTemplates(node.children));
    }
  }
  return result;
}

export function countSpawnableTemplates(nodes: StageTaskTemplate[]): number {
  return flattenTemplates(nodes).length;
}

export function patchTemplateInTree(
  nodes: StageTaskTemplate[],
  templateId: string,
  patch: Partial<StageTaskTemplate>,
): StageTaskTemplate[] {
  return nodes.map((node) => {
    if (node.id === templateId) {
      return sanitizeTaskNode({ ...node, ...patch });
    }
    if (node.children.length === 0) return node;
    return {
      ...node,
      children: patchTemplateInTree(node.children, templateId, patch),
    };
  });
}

export function removeTemplateFromTree(nodes: StageTaskTemplate[], templateId: string): StageTaskTemplate[] {
  return sanitizeStageTemplates(
    nodes
      .filter((node) => node.id !== templateId)
      .map((node) =>
        node.children.length > 0
          ? { ...node, children: removeTemplateFromTree(node.children, templateId) }
          : node,
      ),
  );
}

export function addChildTemplate(
  nodes: StageTaskTemplate[],
  parentId: string,
  child: StageTaskTemplate,
): StageTaskTemplate[] {
  return nodes.map((node) => {
    if (node.id === parentId) {
      return sanitizeTaskNode({
        ...node,
        children: [...node.children, sanitizeTaskNode(child)],
      });
    }
    if (node.children.length === 0) return node;
    return { ...node, children: addChildTemplate(node.children, parentId, child) };
  });
}

export function createStageTaskTemplate(stageTitle: string, index: number): StageTaskTemplate {
  return sanitizeTaskNode(createTaskTemplate(stageTitle, index));
}

export function createSubtaskTemplate(parentTitle: string, index: number): StageTaskTemplate {
  return sanitizeTaskNode({
    id: `task-${crypto.randomUUID()}`,
    title: index === 0 ? `${parentTitle} subtask` : `${parentTitle} subtask ${index + 1}`,
    description: "",
    dependsOn: [],
    children: [],
  });
}

export type TemplateSiblingLocation = {
  parentId: string | null;
  index: number;
  siblingCount: number;
};

export function findTemplateSiblingLocation(
  nodes: StageTaskTemplate[],
  templateId: string,
  parentId: string | null = null,
): TemplateSiblingLocation | null {
  const siblings = sanitizeStageTemplates(nodes);
  for (let index = 0; index < siblings.length; index += 1) {
    const node = siblings[index];
    if (!node) continue;
    if (node.id === templateId) {
      return { parentId, index, siblingCount: siblings.length };
    }
    if (node.children.length > 0) {
      const found = findTemplateSiblingLocation(node.children, templateId, node.id);
      if (found) return found;
    }
  }
  return null;
}

export function canMoveTemplateAmongSiblings(
  nodes: StageTaskTemplate[],
  templateId: string,
  delta: -1 | 1,
): boolean {
  const location = findTemplateSiblingLocation(nodes, templateId);
  if (!location) return false;
  const target = location.index + delta;
  return target >= 0 && target < location.siblingCount;
}

function swapSiblingInTree(
  nodes: StageTaskTemplate[],
  parentId: string | null,
  index: number,
  delta: -1 | 1,
): StageTaskTemplate[] {
  const target = index + delta;
  if (parentId === null) {
    const roots = sanitizeStageTemplates(nodes);
    if (target < 0 || target >= roots.length) return nodes;
    const next = [...roots];
    const current = next[index];
    const swap = next[target];
    if (!current || !swap) return nodes;
    next[index] = swap;
    next[target] = current;
    return next;
  }
  return nodes.map((node) => {
    if (node.id === parentId) {
      const children = sanitizeStageTemplates(node.children);
      if (target < 0 || target >= children.length) return node;
      const next = [...children];
      const current = next[index];
      const swap = next[target];
      if (!current || !swap) return node;
      next[index] = swap;
      next[target] = current;
      return sanitizeTaskNode({ ...node, children: next });
    }
    if (node.children.length === 0) return node;
    return { ...node, children: swapSiblingInTree(node.children, parentId, index, delta) };
  });
}

export function moveTemplateAmongSiblings(
  nodes: StageTaskTemplate[],
  templateId: string,
  delta: -1 | 1,
): StageTaskTemplate[] {
  const location = findTemplateSiblingLocation(nodes, templateId);
  if (!location || !canMoveTemplateAmongSiblings(nodes, templateId, delta)) return nodes;
  return swapSiblingInTree(nodes, location.parentId, location.index, delta);
}

export function findTemplateInTree(
  nodes: StageTaskTemplate[],
  templateId: string,
  depth = 0,
): { template: StageTaskTemplate; depth: number } | null {
  for (const node of sanitizeStageTemplates(nodes)) {
    if (node.id === templateId) return { template: node, depth };
    if (node.children.length > 0) {
      const found = findTemplateInTree(node.children, templateId, depth + 1);
      if (found) return found;
    }
  }
  return null;
}

export type DisplayTemplate = {
  template: StageTaskTemplate;
  depth: number;
};

export function flattenTemplatesForDisplay(
  nodes: StageTaskTemplate[],
  depth = 0,
): DisplayTemplate[] {
  const result: DisplayTemplate[] = [];
  for (const node of sanitizeStageTemplates(nodes)) {
    result.push({ template: node, depth });
    if (node.children.length > 0) {
      result.push(...flattenTemplatesForDisplay(node.children, depth + 1));
    }
  }
  return result;
}

export function countDisplayRows(nodes: StageTaskTemplate[]): number {
  const roots = sanitizeStageTemplates(nodes);
  let count = 1;
  for (const node of roots) {
    count += countSubtreeRows(node);
  }
  return count;
}

function countSubtreeRows(node: StageTaskTemplate): number {
  const children = node.children;
  if (children.length === 0) return 1;
  let count = 1;
  for (const child of children) {
    count += countSubtreeRows(child);
  }
  return count + 1;
}

const TASK_ROW_HEIGHT = 40;
const TASK_ROW_GAP = 8;

function stackHeightForSiblings(nodes: StageTaskTemplate[]): number {
  const siblings = sanitizeStageTemplates(nodes);
  if (siblings.length === 0) return 0;
  return siblings.reduce((total, node, index) => {
    const gap = index > 0 ? TASK_ROW_GAP : 0;
    return total + gap + subtreeStackHeight(node);
  }, 0);
}

function subtreeStackHeight(node: StageTaskTemplate): number {
  const children = sanitizeStageTemplates(node.children);
  const childStack = stackHeightForSiblings(children);
  if (childStack === 0) return TASK_ROW_HEIGHT;
  return TASK_ROW_HEIGHT + TASK_ROW_GAP + childStack;
}

export function templateStackHeight(nodes: StageTaskTemplate[]): number {
  return stackHeightForSiblings(nodes);
}

import type { StageTaskTemplate, WorkflowStage } from "@/lib/api";
import {
  countSpawnableTemplates,
  NODE_ADD_BTN_SIZE,
  sanitizeStageTemplates,
  templateStackHeight,
} from "./template-graph-utils";

export const TASK_REORDER_WIDTH = 24;
export const SUBTASK_CONNECTOR_WIDTH = 28;
export const TASK_ROW_LINK_WIDTH = 20;
export const TASK_NODE_GAP = 8;
export const STAGE_TASK_ADD_STACK = 16 + NODE_ADD_BTN_SIZE;

export function taskRowCanvasWidth(depth: number): number {
  return (
    depth * TASK_DEPTH_INDENT +
    (depth > 0 ? SUBTASK_CONNECTOR_WIDTH : 0) +
    TASK_REORDER_WIDTH +
    TASK_NODE_WIDTH +
    TASK_ROW_LINK_WIDTH +
    NODE_ADD_BTN_SIZE
  );
}

export function maxTaskTreeCanvasWidth(nodes: StageTaskTemplate[]): number {
  let max = 0;
  function walk(node: StageTaskTemplate, depth: number) {
    max = Math.max(max, taskRowCanvasWidth(depth));
    for (const child of sanitizeStageTemplates(node.children ?? [])) {
      walk(child, depth + 1);
    }
  }
  for (const root of sanitizeStageTemplates(nodes)) {
    walk(root, 0);
  }
  return max;
}

function resolveStageColumnWidth(stage: WorkflowStage, stageCardWidth: number): number {
  const templates = stage.taskTemplates ?? [];
  if (templates.length === 0) return stageCardWidth;
  return Math.max(stageCardWidth, maxTaskTreeCanvasWidth(templates));
}

export function stageLayoutKey(stages: WorkflowStage[]): string {
  return stages
    .map((stage) => {
      const templates = stage.taskTemplates ?? [];
      return [
        stage.id,
        countSpawnableTemplates(templates),
        maxTaskTreeCanvasWidth(templates),
        templateStackHeight(templates),
      ].join(":");
    })
    .join("|");
}

export const STAGE_CARD_WIDTH = 280;
export const STAGE_CARD_HEIGHT = 88;
export const STAGE_COLUMN_GAP = 56;
export const STEP_TASK_GAP = 20;
export const TASK_TEMPLATE_HEIGHT = 40;
export const TASK_TEMPLATE_GAP = 8;
export const TASK_NODE_WIDTH = 248;
export const TASK_DEPTH_INDENT = 22;
export const CANVAS_WIDTH = 4800;
export const CANVAS_HEIGHT = 3200;

export type DisplayStage = WorkflowStage & {
  displayX: number;
  displayY: number;
  columnWidth: number;
};

export function slugify(value: string) {
  return value
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

export function stagesForDisplay(stages: WorkflowStage[]): DisplayStage[] {
  const sorted = [...stages].sort((a, b) => a.position - b.position);
  const widths = sorted.map((stage) => resolveStageColumnWidth(stage, STAGE_CARD_WIDTH));
  const totalWidth =
    widths.reduce((sum, width) => sum + width, 0) +
    Math.max(0, sorted.length - 1) * STAGE_COLUMN_GAP;
  let cursorX = Math.max(80, (CANVAS_WIDTH - totalWidth) / 2);
  const maxStack = sorted.reduce(
    (max, stage) => Math.max(max, stageStackHeight(stage)),
    STAGE_CARD_HEIGHT,
  );
  const centerY = Math.max(48, (CANVAS_HEIGHT - maxStack) / 2);
  return sorted.map((stage, index) => {
    const columnWidth = widths[index] ?? STAGE_CARD_WIDTH;
    const displayX = cursorX;
    cursorX += columnWidth + STAGE_COLUMN_GAP;
    return {
      ...stage,
      displayX,
      displayY: centerY,
      columnWidth,
    };
  });
}

function newEntityId(prefix: string) {
  return `${prefix}-${crypto.randomUUID()}`;
}

export function createEmptyStage(position: number): WorkflowStage {
  return {
    id: newEntityId("stage"),
    title: "New step",
    description: "",
    position,
    autoAssignRole: undefined,
    layoutX: null,
    layoutY: null,
    spawnTaskCount: 0,
    taskTemplates: [],
  };
}

export function insertStageAt(
  stages: WorkflowStage[],
  afterIndex: number | null,
  stage: WorkflowStage,
): WorkflowStage[] {
  const sorted = [...stages].sort((a, b) => a.position - b.position);
  const insertAt = afterIndex === null ? 0 : afterIndex + 1;
  const next = [...sorted.slice(0, insertAt), stage, ...sorted.slice(insertAt)];
  return next.map((item, position) => ({ ...item, position }));
}

export function moveStageBy(stages: WorkflowStage[], index: number, delta: -1 | 1): WorkflowStage[] {
  const sorted = [...stages].sort((a, b) => a.position - b.position);
  const target = index + delta;
  if (target < 0 || target >= sorted.length) return stages;
  const next = [...sorted];
  const current = next[index];
  const swap = next[target];
  if (!current || !swap) return stages;
  next[index] = swap;
  next[target] = current;
  return next.map((item, position) => ({ ...item, position }));
}

export function syncStageTemplates(stage: WorkflowStage): WorkflowStage {
  const taskTemplates = sanitizeStageTemplates(stage.taskTemplates ?? []);
  return {
    ...stage,
    taskTemplates,
    spawnTaskCount: countSpawnableTemplates(taskTemplates),
  };
}

export function stageStackHeight(stage: WorkflowStage): number {
  const templates = stage.taskTemplates ?? [];
  const base = STAGE_CARD_HEIGHT + STAGE_TASK_ADD_STACK;
  if (templates.length === 0) return base;
  return base + STEP_TASK_GAP + templateStackHeight(templates);
}

export function normalizeStagePositions(stages: WorkflowStage[]): WorkflowStage[] {
  return [...stages]
    .sort((a, b) => a.position - b.position)
    .map((stage, position) => ({ ...stage, position }));
}

export function screenToCanvas(
  screenX: number,
  screenY: number,
  rect: DOMRect,
  pan: { x: number; y: number },
  zoom: number,
) {
  return {
    x: (screenX - rect.left - pan.x) / zoom,
    y: (screenY - rect.top - pan.y) / zoom,
  };
}

type CanvasPanZoomRefs = {
  getZoom: () => number;
  getPan: () => { x: number; y: number };
  setZoom: (zoom: number) => void;
  setPan: (pan: { x: number; y: number }) => void;
};

export function bindCanvasWheelZoom(
  element: HTMLElement,
  refs: CanvasPanZoomRefs,
  minZoom: number,
  maxZoom: number,
) {
  function onWheel(event: WheelEvent) {
    if (!event.ctrlKey && !event.metaKey) return;
    event.preventDefault();
    const rect = element.getBoundingClientRect();
    const pointerX = event.clientX - rect.left;
    const pointerY = event.clientY - rect.top;
    const currentZoom = refs.getZoom();
    const currentPan = refs.getPan();
    const factor = event.deltaY < 0 ? 1.08 : 0.92;
    const nextZoom = Math.min(maxZoom, Math.max(minZoom, currentZoom * factor));
    const scale = nextZoom / currentZoom;
    refs.setPan({
      x: pointerX - (pointerX - currentPan.x) * scale,
      y: pointerY - (pointerY - currentPan.y) * scale,
    });
    refs.setZoom(nextZoom);
  }
  element.addEventListener("wheel", onWheel, { passive: false });
  return () => element.removeEventListener("wheel", onWheel);
}

import { useCallback, useEffect, useRef, useState } from "react";
import { toast } from "sonner";
import { fetchAllInbox, type InboxItem } from "@/lib/api";
import { markCommentNotified, wasCommentNotified } from "@/lib/read-tasks";
import type { Session } from "@/lib/session";

export function useCommentNotifications(session: Session | null, projectId: string | undefined) {
  const [items, setItems] = useState<InboxItem[]>([]);
  const [loading, setLoading] = useState(true);
  const initializedRef = useRef(false);

  const refresh = useCallback(async () => {
    if (!session || !projectId) return;
    setLoading(true);
    try {
      const commentItems = await fetchAllInbox(session, {
        projectId,
        commentsOnly: true,
        limit: 100,
      });

      for (const item of commentItems) {
        if (!initializedRef.current) {
          markCommentNotified(item.taskId);
          continue;
        }
        if (!wasCommentNotified(item.taskId)) {
          markCommentNotified(item.taskId);
          toast.message("A comment was added to your task", {
            description: item.title || `Task #${item.taskId}`,
          });
        }
      }
      initializedRef.current = true;

      const all = await fetchAllInbox(session, { projectId, limit: 100 });
      setItems(all);
    } finally {
      setLoading(false);
    }
  }, [session, projectId]);

  useEffect(() => {
    void refresh();
    const timer = window.setInterval(() => void refresh(), 30000);
    const onRead = () => void refresh();
    window.addEventListener("task-bridge:read", onRead);
    return () => {
      window.clearInterval(timer);
      window.removeEventListener("task-bridge:read", onRead);
    };
  }, [refresh]);

  const commentItems = items.filter((item) => item.status === "ready");
  const openItems = items.filter((item) => item.status === "sent");

  return { items, commentItems, openItems, loading, refresh };
}

