export class ApiError extends Error {
  status: number;

  constructor(message: string, status: number) {
    super(message);
    this.status = status;
  }
}

function authHeaders(session: Session): Record<string, string> {
  return {
    Accept: "application/json",
    Authorization: `Bearer ${session.token}`,
  };
}

async function parseError(response: Response) {
  try {
    const body = (await response.json()) as {
      error?: string;
      details?: { code?: string };
    };
    if (body.details?.code === "PASSWORD_CHANGE_REQUIRED") {
      return "PASSWORD_CHANGE_REQUIRED";
    }
    if (body.error) return body.error;
  } catch {
    // ignore
  }
  return response.statusText || "Request failed";
}

async function request<T>(
  session: Session,
  path: string,
  init?: RequestInit,
): Promise<T> {
  const response = await fetch(path, {
    ...init,
    headers: {
      ...authHeaders(session),
      ...(init?.headers ?? {}),
    },
  });

  if (response.status === 401) {
    clearSession();
    window.location.href = "/app/login";
    throw new ApiError("Session expired", 401);
  }

  if (!response.ok) {
    const message = await parseError(response);
    if (message === "PASSWORD_CHANGE_REQUIRED") {
      const current = loadSession();
      if (current) {
        saveSession({ ...current, mustChangePassword: true });
      }
      window.location.href = "/app/change-password";
      throw new ApiError("Password change required", 403);
    }
    throw new ApiError(message, response.status);
  }
  if (response.status === 204) {
    return undefined as T;
  }
  const text = await response.text();
  if (!text) {
    return undefined as T;
  }
  return JSON.parse(text) as T;
}

