const READ_KEY = "task-bridge.read-tasks";
const NOTIFY_KEY = "task-bridge.notified-comments";

function isStoredTaskId(value: string | number | boolean | null): value is number {
  return value !== null && String(value) !== value ? false : Number.isInteger(value);
}

function readIds(key: string): number[] {
  try {
    const raw = localStorage.getItem(key);
    if (!raw) return [];
    const parsed = JSON.parse(raw) as (string | number | boolean | null)[];
    if (!Array.isArray(parsed)) return [];
    return parsed.filter(isStoredTaskId);
  } catch {
    return [];
  }
}

function writeIds(key: string, ids: number[]) {
  localStorage.setItem(key, JSON.stringify([...new Set(ids)]));
}

export function isTaskRead(taskId: number) {
  return readIds(READ_KEY).includes(taskId);
}

export function markTaskRead(taskId: number) {
  writeIds(READ_KEY, [...readIds(READ_KEY), taskId]);
  window.dispatchEvent(new CustomEvent("task-bridge:read"));
}

export function wasCommentNotified(taskId: number) {
  return readIds(NOTIFY_KEY).includes(taskId);
}

export function markCommentNotified(taskId: number) {
  writeIds(NOTIFY_KEY, [...readIds(NOTIFY_KEY), taskId]);
}

export function unreadCommentCount(items: { taskId: number; status: string }[]) {
  return items.filter((item) => item.status === "ready" && !isTaskRead(item.taskId)).length;
}

export type UserRole = "admin" | "read-write" | "read";

export type Session = {
  token: string;
  userId: string;
  userName: string;
  userEmail: string;
  userRole: UserRole;
  isSystemAdmin: boolean;
  mustChangePassword?: boolean;
  projectId?: string;
  projectName?: string;
};

const KEY = "task-bridge.session.v2";

export function loadSession(): Session | null {
  try {
    const raw = localStorage.getItem(KEY);
    if (!raw) return null;
    const parsed = JSON.parse(raw) as Session;
    if (!parsed.token?.trim() || !parsed.userId?.trim()) return null;
    return parsed;
  } catch {
    return null;
  }
}

export function saveSession(session: Session) {
  localStorage.setItem(KEY, JSON.stringify(session));
}

export function clearSession() {
  localStorage.removeItem(KEY);
}

export function setSelectedProject(projectId: string, projectName: string) {
  const current = loadSession();
  if (!current) return;
  saveSession({ ...current, projectId, projectName });
}

export function clearSelectedProject() {
  const current = loadSession();
  if (!current) return;
  const { projectId: _p, projectName: _n, ...rest } = current;
  saveSession(rest);
}

import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

export function formatWhen(value?: string | null) {
  if (!value) return "ΓÇö";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return date.toLocaleString();
}

export function formatDuration(ms?: number | null) {
  if (ms == null || ms <= 0) return null;
  if (ms < 1000) return `${ms}ms`;
  const seconds = Math.round(ms / 1000);
  if (seconds < 60) return `${seconds}s`;
  const minutes = Math.floor(seconds / 60);
  const rest = seconds % 60;
  return `${minutes}m ${rest}s`;
}

