export function AdminUsersPage() {
  const session = useSession();

  const [users, setUsers] = useState<PublicUser[]>([]);
  const [loading, setLoading] = useState(true);
  const [addOpen, setAddOpen] = useState(false);
  const [newName, setNewName] = useState("");
  const [newEmail, setNewEmail] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [newRole, setNewRole] = useState("read-write");
  const [adding, setAdding] = useState(false);
  const [addError, setAddError] = useState("");

  const loadUsers = useCallback(async () => {
    if (!session) return;
    try {
      setLoading(true);
      setUsers(await fetchUsers(session));
    } catch {
      toast.error("Failed to load users");
    } finally {
      setLoading(false);
    }
  }, [session]);

  useEffect(() => {
    void loadUsers();
  }, [loadUsers]);

  async function handleAdd(e: React.FormEvent) {
    e.preventDefault();
    if (!session) return;
    setAddError("");
    setAdding(true);
    try {
      const user = await createAppUser(session, {
        name: newName,
        email: newEmail,
        password: newPassword,
        role: newRole,
      });
      setUsers((prev) => [...prev, user]);
      setAddOpen(false);
      setNewName("");
      setNewEmail("");
      setNewPassword("");
      setNewRole("read-write");
      toast.success("User created");
    } catch (err) {
      setAddError(err instanceof Error ? err.message : "Failed to create user");
    } finally {
      setAdding(false);
    }
  }

  async function handleDelete(userId: string, name: string) {
    if (!session) return;
    if (!confirm(`Remove ${name}? This cannot be undone.`)) return;
    try {
      await deleteAppUser(session, userId);
      setUsers((prev) => prev.filter((u) => u.id !== userId));
      toast.success("User removed");
    } catch (err) {
      toast.error(err instanceof Error ? err.message : "Failed to remove user");
    }
  }

  async function handleRoleChange(userId: string, role: string) {
    if (!session) return;
    try {
      const updated = await updateAppUser(session, userId, { role });
      setUsers((prev) => prev.map((u) => (u.id === userId ? updated : u)));
      toast.success("Role updated");
    } catch (err) {
      toast.error(err instanceof Error ? err.message : "Failed to update role");
    }
  }

  if (!session) return null;

  return (
    <div className="flex h-full min-h-0 flex-col">
      <PageHeader
        title="Team members"
        subtitle="Manage who can sign in and what they can access"
        actions={
          <Dialog open={addOpen} onOpenChange={setAddOpen}>
            <DialogTrigger asChild>
              <Button size="sm">
                <Plus className="h-4 w-4" />
                Add member
              </Button>
            </DialogTrigger>
            <DialogContent className="border-white/[0.08] bg-[#111111]">
              <DialogHeader>
                <DialogTitle>Add team member</DialogTitle>
              </DialogHeader>
              <form onSubmit={(e) => void handleAdd(e)} className="space-y-4 pt-2">
                <div className="grid gap-2">
                  <Label>Full name</Label>
                  <Input
                    value={newName}
                    onChange={(e) => setNewName(e.target.value)}
                    placeholder="Jane Smith"
                    required
                  />
                </div>
                <div className="grid gap-2">
                  <Label>Email</Label>
                  <Input
                    type="email"
                    value={newEmail}
                    onChange={(e) => setNewEmail(e.target.value)}
                    placeholder="jane@example.com"
                    required
                  />
                </div>
                <div className="grid gap-2">
                  <Label>Password</Label>
                  <Input
                    type="password"
                    value={newPassword}
                    onChange={(e) => setNewPassword(e.target.value)}
                    placeholder="Min. 6 characters"
                    required
                    minLength={6}
                  />
                </div>
                <div className="grid gap-2">
                  <Label>Role</Label>
                  <Select value={newRole} onChange={(e) => setNewRole(e.target.value)}>
                    <option value="read">Read only</option>
                    <option value="read-write">Read &amp; Write</option>
                    <option value="admin">Admin</option>
                  </Select>
                </div>

                {addError ? (
                  <p className="rounded-md bg-destructive/10 px-3 py-2 text-sm text-destructive">
                    {addError}
                  </p>
                ) : null}

                <div className="flex justify-end gap-2">
                  <Button type="button" variant="ghost" onClick={() => setAddOpen(false)}>
                    Cancel
                  </Button>
                  <Button type="submit" disabled={adding}>
                    {adding ? <Loader2 className="h-4 w-4 animate-spin" /> : null}
                    {adding ? "CreatingΓÇª" : "Create"}
                  </Button>
                </div>
              </form>
            </DialogContent>
          </Dialog>
        }
      />

      <div className="flex-1 overflow-y-auto px-8 py-6">
        {loading ? (
          <div className="flex items-center justify-center py-16">
            <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
          </div>
        ) : users.length === 0 ? (
          <div className="panel-card p-10 text-center text-sm text-muted-foreground">
            No team members yet. Add one to get started.
          </div>
        ) : (
          <div className="panel-card divide-y divide-white/[0.06] overflow-hidden">
            {users.map((user) => (
              <div key={user.id} className="flex items-center justify-between gap-4 px-5 py-4">
                <div className="min-w-0 space-y-0.5">
                  <div className="flex items-center gap-2">
                    <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-primary/15 text-xs font-semibold uppercase text-primary">
                      {user.name.charAt(0)}
                    </div>
                    <span className="truncate font-medium text-white">{user.name}</span>
                    {user.isSystemAdmin ? (
                      <span title="System admin ΓÇö cannot be deleted">
                        <Shield className="h-3.5 w-3.5 shrink-0 text-muted-foreground" />
                      </span>
                    ) : null}
                  </div>
                  <p className="truncate pl-10 text-sm text-muted-foreground">{user.email}</p>
                </div>

                <div className="ml-4 flex shrink-0 items-center gap-3">
                  {user.isSystemAdmin ? (
                    <Badge variant={ROLE_VARIANT[user.role] ?? "outline"}>
                      {ROLE_LABELS[user.role] ?? user.role}
                    </Badge>
                  ) : (
                    <Select
                      value={user.role}
                      onChange={(e) => void handleRoleChange(user.id, e.target.value)}
                      className="h-9 w-auto min-w-[9.5rem] py-1 text-xs"
                    >
                      <option value="read">Read only</option>
                      <option value="read-write">Read &amp; Write</option>
                      <option value="admin">Admin</option>
                    </Select>
                  )}

                  {!user.isSystemAdmin ? (
                    <Button
                      size="icon"
                      variant="ghost"
                      className="h-8 w-8 text-muted-foreground hover:text-destructive"
                      onClick={() => void handleDelete(user.id, user.name)}
                      title="Remove user"
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  ) : null}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

import { useCallback, useEffect, useState } from "react";
import { Link, useParams } from "react-router-dom";
import { ChevronRight, Loader2, MessageSquare, RefreshCw } from "lucide-react";
import { toast } from "sonner";
import { LoadMore } from "@/components/LoadMore";
import { PageHeader } from "@/components/layout/PageHeader";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Skeleton } from "@/components/ui/skeleton";
import { useSession } from "@/hooks/useSession";
import { fetchInbox, type InboxItem } from "@/lib/api";
import { isTaskRead } from "@/lib/read-tasks";
import { cn, formatWhen } from "@/lib/utils";

const PAGE_SIZE = 20;

export function InboxPage() {
  const { projectId } = useParams();
  const session = useSession();
  const [items, setItems] = useState<InboxItem[]>([]);
  const [nextCursor, setNextCursor] = useState<string | null>(null);
  const [hasMore, setHasMore] = useState(false);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);

  const load = useCallback(
    async (cursor: string | undefined, append: boolean) => {
      if (!session || !projectId) return;
      if (append) setLoadingMore(true);
      else setLoading(true);
      try {
        const data = await fetchInbox(session, {
          projectId,
          commentsOnly: true,
          cursor,
          limit: PAGE_SIZE,
        });
        setItems((prev) => (append ? [...prev, ...data.items] : data.items));
        setNextCursor(data.nextCursor);
        setHasMore(data.hasMore);
      } catch (error) {
        toast.error(error instanceof Error ? error.message : "Failed to load inbox");
      } finally {
        setLoading(false);
        setLoadingMore(false);
      }
    },
    [session, projectId],
  );

  const refresh = useCallback(() => {
    void load(undefined, false);
  }, [load]);

  useEffect(() => {
    void load(undefined, false);
  }, [load]);

  useEffect(() => {
    const onRead = () => refresh();
    window.addEventListener("task-bridge:read", onRead);
    return () => window.removeEventListener("task-bridge:read", onRead);
  }, [refresh]);

  const unreadOnPage = items.filter((item) => !isTaskRead(item.taskId)).length;

  return (
    <div className="flex h-full min-h-0 flex-col">
      <PageHeader
        breadcrumb={[
          { label: "Projects", to: "/projects" },
          { label: session?.projectName ?? projectId ?? "Project", to: `/projects/${projectId}/tasks` },
          { label: "Inbox" },
        ]}
        title="Inbox"
        subtitle={unreadOnPage > 0 ? `${unreadOnPage} unread` : "All caught up"}
        actions={
          <Button variant="outline" size="sm" onClick={refresh} disabled={loading || loadingMore}>
            {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : <RefreshCw className="h-4 w-4" />}
            Refresh
          </Button>
        }
      />

      <div className="flex-1 overflow-y-auto p-5">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-lg">
            <MessageSquare className="h-5 w-5 text-primary" />
            Notifications
          </CardTitle>
          <CardDescription>
            {unreadOnPage > 0 ? `${unreadOnPage} unread` : "You are all caught up."}
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-3">
          {loading && items.length === 0 ? (
            <>
              <Skeleton className="h-16 w-full" />
              <Skeleton className="h-16 w-full" />
            </>
          ) : items.length === 0 ? (
            <p className="text-sm text-muted-foreground">No comments yet.</p>
          ) : (
            items.map((item) => {
              const unread = !isTaskRead(item.taskId);
              return (
                <Link
                  key={item.taskId}
                  to={`/projects/${projectId}/tasks/${item.taskId}`}
                  className={cn(
                    "flex items-center justify-between rounded-xl border px-4 py-3 transition-colors",
                    unread
                      ? "border-primary/20 bg-primary/5 hover:border-primary/40 hover:bg-primary/10"
                      : "border-border/60 bg-background/40 opacity-80 hover:bg-accent/20",
                  )}
                >
                  <div className="min-w-0 pr-3">
                    <p className="text-sm font-medium">
                      {unread ? "A comment was added to your task" : "Comment on your task"}
                    </p>
                    <p className="truncate text-sm text-muted-foreground">
                      {item.title || `Task #${item.taskId}`}
                    </p>
                    {item.preview ? (
                      <p className="line-clamp-1 text-xs text-muted-foreground">{item.preview}</p>
                    ) : null}
                    <p className="text-xs text-muted-foreground">
                      {formatWhen(item.activityAt ?? item.updatedAt ?? item.createdAt)}
                    </p>
                  </div>
                  <ChevronRight className="h-4 w-4 shrink-0 text-muted-foreground" />
                </Link>
              );
            })
          )}
          <LoadMore
            loaded={items.length}
            hasMore={hasMore}
            loading={loadingMore}
            onLoadMore={() => void load(nextCursor ?? undefined, true)}
          />
        </CardContent>
      </Card>
      </div>
    </div>
  );
}

import { useCallback, useEffect, useMemo, useState } from "react";
import { useSearchParams } from "react-router-dom";
import { BookOpen, FileText, Loader2, Plus, Save, Trash2 } from "lucide-react";
import { toast } from "sonner";
import { PageHeader } from "@/components/layout/PageHeader";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { useSession } from "@/hooks/useSession";
import {
  createLibrary,
  createLibraryDocument,
  deleteLibrary,
  deleteLibraryDocument,
  fetchLibraries,
  fetchLibrary,
  fetchLibraryDocument,
  saveLibrary,
  saveLibraryDocument,
  type LibraryDetail,
  type LibraryDocument,
  type LibraryDocumentSummary,
  type LibrarySummary,
} from "@/lib/api";
import { cn } from "@/lib/utils";

const UNTITLED_LIBRARY = "Untitled library";
const UNTITLED_DOCUMENT = "Untitled document";

export function LibraryPage() {
  const session = useSession();
  const [searchParams, setSearchParams] = useSearchParams();
  const [libraries, setLibraries] = useState<LibrarySummary[]>([]);
  const [selectedLibraryId, setSelectedLibraryId] = useState<string | null>(null);
  const [libraryDetail, setLibraryDetail] = useState<LibraryDetail | null>(null);
  const [selectedDocumentId, setSelectedDocumentId] = useState<string | null>(null);
  const [documentDetail, setDocumentDetail] = useState<LibraryDocument | null>(null);
  const [libraryTitle, setLibraryTitle] = useState("");
  const [libraryDescription, setLibraryDescription] = useState("");
  const [documentTitle, setDocumentTitle] = useState("");
  const [documentDescription, setDocumentDescription] = useState("");
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [creatingLibrary, setCreatingLibrary] = useState(false);
  const [creatingDocument, setCreatingDocument] = useState(false);

  const docFromUrl = searchParams.get("doc");

  const reloadLibraries = useCallback(async () => {
    if (!session) return;
    const items = await fetchLibraries(session);
    setLibraries(items);
    return items;
  }, [session]);

  const loadLibrary = useCallback(
    async (libraryId: string) => {
      if (!session) return;
      const detail = await fetchLibrary(session, libraryId);
      setLibraryDetail(detail);
      setLibraryTitle(detail.title);
      setLibraryDescription(detail.description);
      return detail;
    },
    [session],
  );

  const loadDocument = useCallback(
    async (documentId: string) => {
      if (!session) return;
      const detail = await fetchLibraryDocument(session, documentId);
      setDocumentDetail(detail);
      setDocumentTitle(detail.title);
      setDocumentDescription(detail.description);
      setSelectedLibraryId(detail.libraryId);
      setSelectedDocumentId(detail.id);
      return detail;
    },
    [session],
  );

  useEffect(() => {
    if (!session) return;
    let active = true;
    async function boot() {
      setLoading(true);
      try {
        const items = await reloadLibraries();
        if (!active) return;
        if (docFromUrl) {
          const doc = await loadDocument(docFromUrl);
          if (doc) await loadLibrary(doc.libraryId);
        } else if (items?.[0]) {
          setSelectedLibraryId(items[0].id);
        }
      } catch (error) {
        toast.error(error instanceof Error ? error.message : "Failed to load library");
      } finally {
        if (active) setLoading(false);
      }
    }
    void boot();
    return () => {
      active = false;
    };
  }, [session, docFromUrl, reloadLibraries, loadDocument, loadLibrary]);

  useEffect(() => {
    if (!session || !selectedLibraryId || docFromUrl) return;
    void loadLibrary(selectedLibraryId).catch((error) => {
      toast.error(error instanceof Error ? error.message : "Failed to load library");
    });
  }, [session, selectedLibraryId, docFromUrl, loadLibrary]);

  useEffect(() => {
    if (!session || !selectedDocumentId) {
      setDocumentDetail(null);
      return;
    }
    void loadDocument(selectedDocumentId).catch((error) => {
      toast.error(error instanceof Error ? error.message : "Failed to load document");
    });
  }, [session, selectedDocumentId, loadDocument]);

  const documents = useMemo<LibraryDocumentSummary[]>(
    () => libraryDetail?.documents ?? [],
    [libraryDetail?.documents],
  );

  const selectedLibrary = libraries.find((entry) => entry.id === selectedLibraryId) ?? null;

  function selectDocument(documentId: string) {
    setSelectedDocumentId(documentId);
    setSearchParams({ doc: documentId });
  }

  function selectLibrary(libraryId: string) {
    setSelectedLibraryId(libraryId);
    setSelectedDocumentId(null);
    setSearchParams({});
  }

  async function handleCreateLibrary() {
    if (!session) return;
    setCreatingLibrary(true);
    try {
      const created = await createLibrary(session, { title: UNTITLED_LIBRARY });
      await reloadLibraries();
      setSelectedLibraryId(created.id);
      setLibraryDetail(created);
      setLibraryTitle(created.title);
      setLibraryDescription(created.description);
      setSelectedDocumentId(null);
      setSearchParams({});
      toast.success("Library created");
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to create library");
    } finally {
      setCreatingLibrary(false);
    }
  }

  async function handleSaveLibrary() {
    if (!session || !selectedLibraryId) return;
    setSaving(true);
    try {
      const saved = await saveLibrary(session, selectedLibraryId, {
        title: libraryTitle,
        description: libraryDescription,
      });
      setLibraryDetail(saved);
      await reloadLibraries();
      toast.success("Library saved");
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to save library");
    } finally {
      setSaving(false);
    }
  }

  async function handleDeleteLibrary() {
    if (!session || !selectedLibraryId) return;
    if (!window.confirm("Delete this library and all documents?")) return;
    try {
      await deleteLibrary(session, selectedLibraryId);
      const items = await reloadLibraries();
      setSelectedLibraryId(items?.[0]?.id ?? null);
      setSelectedDocumentId(null);
      setSearchParams({});
      toast.success("Library deleted");
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to delete library");
    }
  }

  async function handleCreateDocument() {
    if (!session || !selectedLibraryId) return;
    setCreatingDocument(true);
    try {
      const created = await createLibraryDocument(session, selectedLibraryId, {
        title: UNTITLED_DOCUMENT,
      });
      await loadLibrary(selectedLibraryId);
      selectDocument(created.id);
      toast.success("Document created");
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to create document");
    } finally {
      setCreatingDocument(false);
    }
  }

  async function handleSaveDocument() {
    if (!session || !selectedLibraryId || !selectedDocumentId) return;
    setSaving(true);
    try {
      await saveLibraryDocument(session, selectedLibraryId, selectedDocumentId, {
        title: documentTitle,
        description: documentDescription,
      });
      await loadLibrary(selectedLibraryId);
      toast.success("Document saved");
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to save document");
    } finally {
      setSaving(false);
    }
  }

  async function handleDeleteDocument() {
    if (!session || !selectedLibraryId || !selectedDocumentId) return;
    if (!window.confirm("Delete this document?")) return;
    try {
      await deleteLibraryDocument(session, selectedLibraryId, selectedDocumentId);
      setSelectedDocumentId(null);
      setSearchParams({});
      await loadLibrary(selectedLibraryId);
      toast.success("Document deleted");
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to delete document");
    }
  }

  if (!session) return null;

  return (
    <div className="flex h-full min-h-0 flex-col overflow-hidden">
      <PageHeader
        title="Library"
        subtitle={
          loading
            ? "LoadingΓÇª"
            : libraries.length > 0
              ? `${libraries.length} librar${libraries.length === 1 ? "y" : "ies"} ┬╖ link docs to epics`
              : "Shared docs for epics"
        }
      />

      <div className="flex min-h-0 flex-1">
          <aside className="flex w-[240px] shrink-0 flex-col border-r border-white/[0.07] bg-black">
            <div className="flex items-center justify-between border-b border-white/[0.07] px-3 py-3">
              <p className="px-1 text-[10px] font-semibold uppercase tracking-[0.14em] text-muted-foreground">
                Libraries
              </p>
              <Button
                type="button"
                size="icon"
                variant="outline"
                className="h-8 w-8 shrink-0"
                disabled={creatingLibrary}
                onClick={() => void handleCreateLibrary()}
              >
                {creatingLibrary ? <Loader2 className="h-4 w-4 animate-spin" /> : <Plus className="h-4 w-4" />}
              </Button>
            </div>
            <div className="flex-1 space-y-0.5 overflow-y-auto p-2">
              {loading ? (
                <div className="flex justify-center py-8">
                  <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
                </div>
              ) : libraries.length === 0 ? (
                <p className="px-3 py-4 text-xs text-muted-foreground">No libraries yet. Use + to add one.</p>
              ) : (
                libraries.map((entry) => (
                  <button
                    key={entry.id}
                    type="button"
                    onClick={() => selectLibrary(entry.id)}
                    className={cn(
                      "w-full rounded-lg px-3 py-2.5 text-left transition-colors",
                      selectedLibraryId === entry.id
                        ? "bg-white/[0.09] text-white"
                        : "text-muted-foreground hover:bg-white/[0.04] hover:text-foreground",
                    )}
                  >
                    <p className="truncate text-sm font-medium">{entry.title}</p>
                    <p className="mt-0.5 text-xs text-muted-foreground">
                      {entry.documentCount} document{entry.documentCount === 1 ? "" : "s"}
                    </p>
                  </button>
                ))
              )}
            </div>
          </aside>

          <aside
            className={cn(
              "flex w-[260px] shrink-0 flex-col border-r border-white/[0.07] bg-[#0a0a0a]",
              !selectedLibraryId && "opacity-60",
            )}
          >
            <div className="flex items-center justify-between border-b border-white/[0.07] px-3 py-3">
              <p className="px-1 text-[10px] font-semibold uppercase tracking-[0.14em] text-muted-foreground">
                Documents
              </p>
              <Button
                type="button"
                size="icon"
                variant="outline"
                className="h-8 w-8 shrink-0"
                disabled={!selectedLibraryId || creatingDocument}
                onClick={() => void handleCreateDocument()}
              >
                {creatingDocument ? <Loader2 className="h-4 w-4 animate-spin" /> : <Plus className="h-4 w-4" />}
              </Button>
            </div>
            <div className="flex-1 overflow-y-auto p-2">
              {!selectedLibraryId ? (
                <p className="px-3 py-4 text-xs text-muted-foreground">Select a library first.</p>
              ) : documents.length === 0 ? (
                <p className="px-3 py-4 text-xs text-muted-foreground">No documents yet. Use + to add one.</p>
              ) : (
                documents.map((entry) => (
                  <button
                    key={entry.id}
                    type="button"
                    onClick={() => selectDocument(entry.id)}
                    className={cn(
                      "mb-0.5 flex w-full items-start gap-2 rounded-lg px-3 py-2.5 text-left transition-colors",
                      selectedDocumentId === entry.id
                        ? "bg-primary/15 text-primary"
                        : "text-foreground hover:bg-white/[0.04]",
                    )}
                  >
                    <FileText className="mt-0.5 h-4 w-4 shrink-0 opacity-70" />
                    <span className="min-w-0 truncate text-sm font-medium">{entry.title}</span>
                  </button>
                ))
              )}
            </div>
          </aside>

          <section className="flex min-w-0 flex-1 flex-col overflow-hidden bg-[#080808]">
            <div className="flex shrink-0 items-center justify-between gap-3 border-b border-white/[0.07] px-6 py-3">
              <div className="min-w-0">
                <div className="flex items-center gap-2">
                  {selectedDocumentId ? (
                    <FileText className="h-4 w-4 shrink-0 text-muted-foreground" />
                  ) : (
                    <BookOpen className="h-4 w-4 shrink-0 text-muted-foreground" />
                  )}
                  <h2 className="truncate text-base font-semibold tracking-tight text-white">
                    {selectedDocumentId
                      ? documentTitle || "Document"
                      : selectedLibrary
                        ? libraryTitle || selectedLibrary.title
                        : "Library"}
                  </h2>
                </div>
                {selectedDocumentId && documentDetail ? (
                  <p className="mt-0.5 truncate pl-6 text-xs text-muted-foreground">
                    {documentDetail.libraryTitle} ┬╖ {documentDetail.linkCount} epic link
                    {documentDetail.linkCount === 1 ? "" : "s"}
                  </p>
                ) : selectedLibraryId ? (
                  <p className="mt-0.5 pl-6 text-xs text-muted-foreground">
                    {documents.length} document{documents.length === 1 ? "" : "s"} in this library
                  </p>
                ) : null}
              </div>
              <div className="flex shrink-0 items-center gap-2">
                {selectedDocumentId ? (
                  <>
                    <Button
                      type="button"
                      variant="outline"
                      size="sm"
                      onClick={() => void handleDeleteDocument()}
                    >
                      <Trash2 className="h-4 w-4" />
                      Delete
                    </Button>
                    <Button type="button" size="sm" disabled={saving} onClick={() => void handleSaveDocument()}>
                      {saving ? <Loader2 className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
                      Save
                    </Button>
                  </>
                ) : selectedLibraryId ? (
                  <>
                    <Button
                      type="button"
                      variant="outline"
                      size="sm"
                      onClick={() => void handleDeleteLibrary()}
                    >
                      <Trash2 className="h-4 w-4" />
                      Delete
                    </Button>
                    <Button type="button" size="sm" disabled={saving} onClick={() => void handleSaveLibrary()}>
                      {saving ? <Loader2 className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
                      Save
                    </Button>
                  </>
                ) : null}
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-6">
              {selectedDocumentId ? (
                <div className="mx-auto max-w-2xl space-y-4">
                  <div className="space-y-1.5">
                    <label className="text-xs font-medium text-muted-foreground">Title</label>
                    <Input
                      value={documentTitle}
                      onChange={(event) => setDocumentTitle(event.target.value)}
                      className="border-white/[0.1] bg-[#111111]"
                    />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-xs font-medium text-muted-foreground">Content</label>
                    <Textarea
                      value={documentDescription}
                      onChange={(event) => setDocumentDescription(event.target.value)}
                      rows={18}
                      className="min-h-[360px] resize-y rounded-xl border-white/[0.1] bg-[#111111]"
                      placeholder="Notes, specs, links, acceptance criteriaΓÇª"
                    />
                  </div>
                </div>
              ) : selectedLibraryId ? (
                <div className="mx-auto max-w-2xl space-y-4">
                  <div className="space-y-1.5">
                    <label className="text-xs font-medium text-muted-foreground">Title</label>
                    <Input
                      value={libraryTitle}
                      onChange={(event) => setLibraryTitle(event.target.value)}
                      className="border-white/[0.10] bg-[#111111]"
                    />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-xs font-medium text-muted-foreground">Description</label>
                    <Textarea
                      value={libraryDescription}
                      onChange={(event) => setLibraryDescription(event.target.value)}
                      rows={8}
                      className="resize-y rounded-xl border-white/[0.10] bg-[#111111]"
                      placeholder="What this library is for"
                    />
                  </div>
                  {documents.length === 0 ? (
                    <div className="panel-card flex flex-col items-center px-6 py-10 text-center">
                      <FileText className="mb-3 h-8 w-8 text-muted-foreground/50" />
                      <p className="text-sm text-muted-foreground">
                        Add a document with +, then link it from an epic detail page.
                      </p>
                    </div>
                  ) : (
                    <p className="text-sm text-muted-foreground">
                      Select a document from the list or create a new one with +.
                    </p>
                  )}
                </div>
              ) : (
                <div className="panel-card mx-auto flex max-w-md flex-col items-center px-8 py-14 text-center">
                  <BookOpen className="mb-4 h-10 w-10 text-muted-foreground/50" />
                  <p className="text-sm font-medium text-white">Create your first library</p>
                  <p className="mt-2 text-sm text-muted-foreground">
                    Press + in the sidebar, then name it in the editor.
                  </p>
                </div>
              )}
            </div>
          </section>
      </div>
    </div>
  );
}

import { useEffect, useState } from "react";
import { QRCodeSVG } from "qrcode.react";
import { Download, Smartphone } from "lucide-react";
import { useParams } from "react-router-dom";
import { SensitiveField, SensitiveReveal } from "@/components/SensitiveField";
import { PageHeader } from "@/components/layout/PageHeader";
import { Button } from "@/components/ui/button";
import { useSession } from "@/hooks/useSession";
import { buildMobileQrData } from "@/lib/api";

export function MobilePage() {
  const { projectId } = useParams();
  const session = useSession();

  const mobileUri = session ? buildMobileQrData(session) : undefined;

  type ApkRelease =
    | { available: false }
    | { available: true; downloadUrl: string; sizeBytes: number; fileName: string };

  const [apkRelease, setApkRelease] = useState<ApkRelease>();

  useEffect(() => {
    let active = true;
    async function loadApkRelease() {
      try {
        const response = await fetch("/mobile/release");
        if (!response.ok) return;
        const data = (await response.json()) as ApkRelease;
        if (active) setApkRelease(data);
      } catch {
        if (active) setApkRelease({ available: false });
      }
    }
    void loadApkRelease();
    return () => {
      active = false;
    };
  }, []);

  async function copy(text: string) {
    await navigator.clipboard.writeText(text);
  }

  return (
    <div className="flex h-full min-h-0 flex-col">
      <PageHeader
        breadcrumb={[
          { label: "Projects", to: "/projects" },
          {
            label: session?.projectName ?? projectId ?? "Project",
            to: `/projects/${projectId}/tasks`,
          },
          { label: "Mobile" },
        ]}
        title="Mobile"
        subtitle="Connect the Android app"
      />

      <div className="flex-1 overflow-y-auto p-8">
        <div className="mx-auto max-w-xl space-y-8">
          <div className="panel-card space-y-6 p-6">
            <div className="flex items-center gap-3">
              <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-primary/15">
                <Smartphone className="h-5 w-5 text-primary" />
              </div>
              <div>
                <p className="font-semibold text-white">Connect mobile app</p>
                <p className="text-sm text-muted-foreground">
                  Scan the QR code in the Android app to sign in instantly.
                </p>
              </div>
            </div>

            {mobileUri ? (
              <SensitiveReveal label="Show QR code" hideLabel="Hide QR">
                <div className="flex flex-col items-center gap-4">
                  <div className="inline-flex rounded-2xl bg-white p-4 shadow-sm">
                    <QRCodeSVG value={mobileUri} size={240} level="L" includeMargin />
                  </div>
                  <p className="text-center text-xs leading-relaxed text-muted-foreground">
                    Scan with the Task Bridge Android app. The QR encodes your personal token ΓÇö keep it private.
                  </p>
                </div>
              </SensitiveReveal>
            ) : null}

            <div className="space-y-3">
              <SensitiveField
                label="Your token"
                value={session?.token ?? "ΓÇö"}
                onCopy={session ? () => void copy(session.token) : undefined}
              />
              <SensitiveField
                label="Deep link"
                value={mobileUri ?? "ΓÇö"}
                onCopy={mobileUri ? () => void copy(mobileUri) : undefined}
              />
            </div>
          </div>

          {apkRelease?.available && apkRelease.downloadUrl ? (
            <div className="panel-card space-y-4 p-6">
              <div className="flex flex-wrap items-center gap-3">
                <Button asChild>
                  <a href={apkRelease.downloadUrl} download={apkRelease.fileName}>
                    <Download className="mr-2 h-4 w-4" />
                    Download APK
                  </a>
                </Button>
                {apkRelease.sizeBytes ? (
                  <span className="text-sm text-muted-foreground">
                    {(apkRelease.sizeBytes / (1024 * 1024)).toFixed(1)} MB
                  </span>
                ) : null}
              </div>
            </div>
          ) : null}
        </div>
      </div>
    </div>
  );
}

import { useEffect, useMemo, useState } from "react";
import { Link, useParams } from "react-router-dom";
import { Loader2, Pencil } from "lucide-react";
import { toast } from "sonner";
import { PageHeader } from "@/components/layout/PageHeader";
import { CreateTaskModal } from "@/components/CreateTaskModal";
import { DescriptionEditorModal } from "@/components/DescriptionEditorModal";
import { TaskLibraryLinks } from "@/components/TaskLibraryLinks";
import { EpicProgressCanvas } from "@/components/workflow/EpicProgressCanvas";
import { EpicTaskInspector } from "@/components/workflow/EpicTaskInspector";
import { MarkdownView } from "@/components/MarkdownView";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Skeleton } from "@/components/ui/skeleton";
import { Textarea } from "@/components/ui/textarea";
import { useSession } from "@/hooks/useSession";
import {
  addTaskComment,
  createTask,
  fetchProjectWorkflow,
  fetchTask,
  updateTaskDescription,
  updateTaskWorkStatus,
  type ProjectMember,
  type TaskComment,
  type TaskDetail,
  type WorkflowStage,
  type WorkStatus,
} from "@/lib/api";
import { markTaskRead } from "@/lib/read-tasks";
import { formatWhen } from "@/lib/utils";

function parseTime(value: string | null | undefined) {
  if (!value) return 0;
  const parsed = Date.parse(value);
  return Number.isNaN(parsed) ? 0 : parsed;
}

function sortComments(comments: TaskComment[]) {
  return [...comments].sort((a, b) => parseTime(a.at) - parseTime(b.at));
}

function authorLabel(comment: TaskComment) {
  if (comment.authorId.trim()) return comment.authorId.trim();
  if (comment.by.trim()) return comment.by.trim();
  if (comment.role === "system") return "System";
  return "User";
}

export function TaskPage() {
  const { projectId = "", taskId: taskIdParam } = useParams();
  const taskId = Number(taskIdParam);
  const session = useSession();
  const [detail, setDetail] = useState<TaskDetail | null>(null);
  const [workflowStages, setWorkflowStages] = useState<WorkflowStage[]>([]);
  const [members, setMembers] = useState<ProjectMember[]>([]);
  const [actAsMemberId, setActAsMemberId] = useState("");
  const [loading, setLoading] = useState(true);
  const [commentText, setCommentText] = useState("");
  const [sending, setSending] = useState(false);
  const [updatingStatus, setUpdatingStatus] = useState(false);
  const [updatingSubtaskStatus, setUpdatingSubtaskStatus] = useState(false);
  const [addTaskTarget, setAddTaskTarget] = useState<{
    parentId: number;
    stageId: string | null;
    label: string;
  } | null>(null);
  const [creatingTask, setCreatingTask] = useState(false);
  const [descriptionOpen, setDescriptionOpen] = useState(false);
  const [savingDescription, setSavingDescription] = useState(false);
  const [selectedSubtaskId, setSelectedSubtaskId] = useState<number | null>(null);

  useEffect(() => {
    if (!session || !Number.isFinite(taskId)) return;
    const activeSession = session;
    let active = true;

    async function load() {
      setLoading(true);
      try {
        const data = await fetchTask(activeSession, taskId);
        if (!active) return;
        if (data.status === "ready") {
          markTaskRead(taskId);
        }
        setDetail(data);
        if (data.isEpic) {
          const workflowProjectId = data.projectId ?? projectId;
          if (workflowProjectId) {
            const workflow = await fetchProjectWorkflow(activeSession, workflowProjectId);
            if (active) {
              setWorkflowStages(workflow.stages);
              setMembers(workflow.members);
              setActAsMemberId((current) => {
                if (current && workflow.members.some((member) => member.id === current)) return current;
                return workflow.members[0]?.id ?? "";
              });
            }
          }
        }
      } catch (error) {
        toast.error(error instanceof Error ? error.message : "Failed to load task");
      } finally {
        if (active) setLoading(false);
      }
    }

    void load();
    return () => {
      active = false;
    };
  }, [session, taskId, projectId]);

  const comments = useMemo(
    () => sortComments(detail?.comments ?? []),
    [detail?.comments],
  );
  const description = detail?.description?.trim() ? detail.description : null;
  const subtasks = detail?.subtasks ?? [];
  const selectedSubtask = useMemo(
    () => subtasks.find((entry) => entry.taskId === selectedSubtaskId) ?? null,
    [subtasks, selectedSubtaskId],
  );
  const epicProgress = useMemo(() => {
    const total = subtasks.length;
    const done = subtasks.filter((entry) => entry.done).length;
    const active = subtasks.filter((entry) => entry.workStatus === "in_progress").length;
    return { total, done, active };
  }, [subtasks]);

  async function reloadEpic() {
    if (!session || !Number.isFinite(taskId)) return;
    const data = await fetchTask(session, taskId);
    setDetail(data);
    return data;
  }

  async function handleWorkStatus(workStatus: WorkStatus) {
    if (!session || !Number.isFinite(taskId)) return;
    const actor = members.find((member) => member.id === actAsMemberId);
    if (!actor) {
      toast.error("Pick a project member on the epic canvas first");
      return;
    }
    setUpdatingStatus(true);
    try {
      const data = await updateTaskWorkStatus(session, taskId, workStatus, actor.name);
      setDetail(data);
      toast.success("Status updated");
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to update status");
    } finally {
      setUpdatingStatus(false);
    }
  }

  async function handleSubtaskStatus(subtaskId: number, workStatus: WorkStatus) {
    if (!session) return;
    const actor = members.find((member) => member.id === actAsMemberId);
    setUpdatingSubtaskStatus(true);
    try {
      await updateTaskWorkStatus(session, subtaskId, workStatus, actor?.name ?? "web");
      const data = await reloadEpic();
      if (data) {
        const refreshed = data.subtasks?.find((entry) => entry.taskId === subtaskId);
        if (refreshed) setSelectedSubtaskId(subtaskId);
      }
      toast.success("Status updated");
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to update status");
    } finally {
      setUpdatingSubtaskStatus(false);
    }
  }

  async function handleCreateTask(title: string, description: string) {
    if (!session || !addTaskTarget) return;
    const trimmed = title.trim();
    if (!trimmed) return;
    setCreatingTask(true);
    try {
      const created = await createTask(session, {
        parentId: addTaskTarget.parentId,
        title: trimmed,
        description: description.trim() || undefined,
        stageId: addTaskTarget.stageId ?? undefined,
      });
      const data = await reloadEpic();
      const createdId = Number(created.id);
      if (Number.isFinite(createdId)) {
        setSelectedSubtaskId(createdId);
      } else if (data?.subtasks?.length) {
        const match = data.subtasks.find((entry) => entry.title === trimmed);
        if (match) setSelectedSubtaskId(match.taskId);
      }
      toast.success(`Added to ${addTaskTarget.label}`);
      setAddTaskTarget(null);
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to create task");
    } finally {
      setCreatingTask(false);
    }
  }

  async function handleSaveDescription(next: string) {
    if (!session || !Number.isFinite(taskId)) return;
    setSavingDescription(true);
    try {
      const data = await updateTaskDescription(session, taskId, next);
      setDetail(data);
      setDescriptionOpen(false);
      toast.success("Description saved");
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to save description");
    } finally {
      setSavingDescription(false);
    }
  }

  async function handleSendComment() {
    if (!session || !Number.isFinite(taskId)) return;
    const text = commentText.trim();
    if (!text) return;

    setSending(true);
    try {
      const data = await addTaskComment(session, taskId, text);
      setDetail(data);
      setCommentText("");
      toast.success("Comment added");
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to send comment");
    } finally {
      setSending(false);
    }
  }

  const tasksPath = `/projects/${projectId}/tasks`;
  const crumbs = [
    { label: "Projects", to: "/projects" },
    { label: session?.projectName ?? projectId ?? "Project", to: tasksPath },
    { label: "Epics", to: tasksPath },
  ];
  if (detail?.parent) {
    crumbs.push({ label: detail.parent.title, to: `${tasksPath}/${detail.parent.taskId}` });
  }

  return (
    <div className="flex h-full min-h-0 flex-col">
      <PageHeader
        breadcrumb={crumbs}
        title={loading ? "LoadingΓÇª" : detail?.title ?? "Task"}
      />

      <div className="flex-1 overflow-y-auto px-8 py-5 pb-10">
        <div className="flex flex-col gap-5">
      {loading ? (
        <Skeleton className="h-96 w-full rounded-xl" />
      ) : detail ? (
        <>
          <header className="space-y-3 border-b border-border pb-4">
                <div className="flex flex-wrap gap-2 text-sm text-muted-foreground">
                  {detail.parent ? (
                    <Link
                      to={`/projects/${projectId}/tasks/${detail.parent.taskId}`}
                      className="rounded-full border px-2 py-0.5 hover:text-foreground"
                    >
                      Parent: {detail.parent.title}
                    </Link>
                  ) : null}
                  {detail.isEpic && detail.stage?.title ? (
                    <span className="rounded-full border border-primary/30 bg-primary/10 px-2 py-0.5 text-primary">
                      Active step: {detail.stage.title}
                    </span>
                  ) : null}
                  {detail.isEpic && epicProgress.total > 0 ? (
                    <span className="rounded-full border px-2 py-0.5 text-foreground">
                      {epicProgress.done}/{epicProgress.total} tasks done
                      {epicProgress.active > 0 ? ` ┬╖ ${epicProgress.active} in progress` : ""}
                    </span>
                  ) : null}
                  {!detail.isEpic && detail.workStatusLabel ? (
                    <span className="rounded-full border px-2 py-0.5 text-foreground">{detail.workStatusLabel}</span>
                  ) : null}
                  {detail.assignee ? <span>Assignee: {detail.assignee}</span> : null}
                </div>
          </header>

          {detail.isEpic ? (
            <section className="panel-card p-5">
              <div className="flex items-center justify-between gap-3">
                <h2 className="text-sm font-semibold text-white">Description</h2>
                <Button type="button" variant="ghost" size="sm" onClick={() => setDescriptionOpen(true)}>
                  <Pencil className="mr-1.5 h-3.5 w-3.5" />
                  {description ? "Edit" : "Add"}
                </Button>
              </div>
              <div className="mt-3">
                {description ? (
                  <MarkdownView content={description} />
                ) : (
                  <p className="text-sm text-muted-foreground">
                    No description yet ΓÇö add goals, scope, or acceptance notes.
                  </p>
                )}
              </div>
            </section>
          ) : null}

          {session && detail.isEpic ? (
            <TaskLibraryLinks
              session={session}
              taskId={taskId}
              links={detail.libraryLinks ?? []}
              onChange={(libraryLinks) =>
                setDetail((current) => (current ? { ...current, libraryLinks } : current))
              }
            />
          ) : null}

          {detail.isEpic ? (
            <div className="flex min-h-[min(72vh,680px)] overflow-hidden rounded-xl border border-white/[0.06] bg-[#080808]">
              <EpicProgressCanvas
                stages={workflowStages}
                epicId={taskId}
                epicStageId={detail.stageId ?? null}
                subtasks={subtasks}
                workflowState={detail.workflowState ?? []}
                selectedTaskId={selectedSubtaskId}
                onSelectTask={setSelectedSubtaskId}
                onAddTaskToStage={(stageId, stageTitle) =>
                  setAddTaskTarget({ parentId: taskId, stageId, label: `step "${stageTitle}"` })
                }
                onAddSubtask={(parentTaskId, parentTitle, stageId) =>
                  setAddTaskTarget({ parentId: parentTaskId, stageId, label: `subtask of "${parentTitle}"` })
                }
              />
              <EpicTaskInspector
                projectId={projectId}
                epicId={taskId}
                subtasks={subtasks}
                selected={selectedSubtask}
                members={members}
                actAsMemberId={actAsMemberId}
                updatingStatus={updatingSubtaskStatus}
                onActAsMemberChange={setActAsMemberId}
                onClose={() => setSelectedSubtaskId(null)}
                onStatusChange={(subtaskId, status) => void handleSubtaskStatus(subtaskId, status)}
              />
            </div>
          ) : null}

          {!detail.isEpic ? (
            <Card>
              <CardHeader className="pb-2">
                <CardTitle className="text-base font-semibold">Work status</CardTitle>
              </CardHeader>
              <CardContent className="space-y-3 pt-0">
                <p className="text-sm text-muted-foreground">
                  Step: {detail.stage?.title ?? detail.stageId ?? "ΓÇö"}
                </p>
                <div className="flex flex-wrap gap-2">
                  {(["todo", "in_progress", "done"] as WorkStatus[]).map((status) => (
                    <Button
                      key={status}
                      size="sm"
                      variant={detail.workStatus === status ? "default" : "outline"}
                      disabled={updatingStatus}
                      onClick={() => void handleWorkStatus(status)}
                    >
                      {status === "in_progress" ? "In progress" : status === "done" ? "Done" : "Todo"}
                    </Button>
                  ))}
                </div>
              </CardContent>
            </Card>
          ) : null}

          {!detail.isEpic && description ? (
            <Card>
              <CardHeader className="pb-2">
                <CardTitle className="text-base font-semibold">Description</CardTitle>
              </CardHeader>
              <CardContent className="pt-0">
                <MarkdownView content={description} />
              </CardContent>
            </Card>
          ) : null}

          {detail.isEpic ? (
            <DescriptionEditorModal
              open={descriptionOpen}
              onOpenChange={setDescriptionOpen}
              title="Epic description"
              value={detail.description ?? ""}
              onSave={(next) => void handleSaveDescription(next)}
              placeholder="Goals, scope, links, acceptance notesΓÇª"
              saving={savingDescription}
            />
          ) : null}

          {detail.isEpic ? (
            <CreateTaskModal
              open={addTaskTarget !== null}
              onOpenChange={(open) => {
                if (!open) setAddTaskTarget(null);
              }}
              targetLabel={addTaskTarget?.label ?? null}
              saving={creatingTask}
              onCreate={(title, description) => void handleCreateTask(title, description)}
            />
          ) : null}

          {!detail.isEpic ? (
            <Card>
              <CardHeader className="pb-2">
                <CardTitle className="text-base font-semibold">Comments</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4 pt-0">
                {comments.length === 0 ? (
                  <p className="text-sm text-muted-foreground">No comments yet.</p>
                ) : (
                  <div className="divide-y divide-border">
                    {comments.map((comment) => (
                      <CommentRow key={comment.id} comment={comment} />
                    ))}
                  </div>
                )}

                <div className="border-t border-border pt-4">
                  <Textarea
                    value={commentText}
                    onChange={(event) => setCommentText(event.target.value)}
                    placeholder="Add a commentΓÇª"
                    rows={2}
                    disabled={sending}
                    className="min-h-[56px] resize-y"
                    onKeyDown={(event) => {
                      if (event.key === "Enter" && (event.metaKey || event.ctrlKey)) {
                        event.preventDefault();
                        void handleSendComment();
                      }
                    }}
                  />
                  <div className="mt-2 flex justify-end">
                    <Button
                      type="button"
                      size="sm"
                      variant="secondary"
                      onClick={() => void handleSendComment()}
                      disabled={sending || !commentText.trim()}
                    >
                      {sending ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : null}
                      {sending ? "SavingΓÇª" : "Comment"}
                    </Button>
                  </div>
                </div>
              </CardContent>
            </Card>
          ) : null}
        </>
      ) : (
        <p className="text-sm text-muted-foreground">Task not found.</p>
      )}
        </div>
      </div>
    </div>
  );
}

function CommentRow({ comment }: { comment: TaskComment }) {
  const name = authorLabel(comment);
  const body = comment.body ?? comment.text ?? null;
  const tags = comment.tags ?? [];

  return (
    <article className="w-full py-3 first:pt-0 last:pb-0">
      <p className="text-xs text-muted-foreground">
        <span className="font-medium text-foreground">{name}</span>
        {tags.length > 0 ? <> ┬╖ {tags.join(", ")}</> : null}
        {comment.at ? <> ┬╖ {formatWhen(comment.at)}</> : null}
      </p>
      <div className="mt-1 w-full">
        <MarkdownView content={body} />
      </div>
    </article>
  );
}

import { useCallback, useEffect, useState } from "react";
import { Link, useParams } from "react-router-dom";
import { ChevronRight, Loader2, Plus, RefreshCw, SendHorizontal } from "lucide-react";
import { toast } from "sonner";
import { LoadMore } from "@/components/LoadMore";
import { PageHeader } from "@/components/layout/PageHeader";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Skeleton } from "@/components/ui/skeleton";
import { Textarea } from "@/components/ui/textarea";
import { useSession } from "@/hooks/useSession";
import { createEpic, fetchInbox, type InboxItem } from "@/lib/api";
import { formatWhen } from "@/lib/utils";

const PAGE_SIZE = 30;

function statusDot(status: string) {
  if (status === "ready") return "bg-emerald-500";
  if (status === "sent") return "bg-sky-500";
  return "bg-amber-500";
}

export function TasksPage() {
  const { projectId } = useParams();
  const session = useSession();
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [sending, setSending] = useState(false);
  const [items, setItems] = useState<InboxItem[]>([]);
  const [nextCursor, setNextCursor] = useState<string | null>(null);
  const [hasMore, setHasMore] = useState(false);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [showComposer, setShowComposer] = useState(false);

  const load = useCallback(
    async (cursor: string | undefined, append: boolean) => {
      if (!session || !projectId) return;
      if (append) setLoadingMore(true);
      else setLoading(true);
      try {
        const data = await fetchInbox(session, {
          projectId,
          epicsOnly: true,
          cursor,
          limit: PAGE_SIZE,
        });
        setItems((prev) => (append ? [...prev, ...data.items] : data.items));
        setNextCursor(data.nextCursor);
        setHasMore(data.hasMore);
      } catch (error) {
        toast.error(error instanceof Error ? error.message : "Failed to load tasks");
      } finally {
        setLoading(false);
        setLoadingMore(false);
      }
    },
    [session, projectId],
  );

  const refresh = useCallback(() => {
    void load(undefined, false);
  }, [load]);

  useEffect(() => {
    void load(undefined, false);
  }, [load]);

  async function submit() {
    if (!session || !projectId) return;
    const trimmedTitle = title.trim();
    if (!trimmedTitle) return;
    setSending(true);
    try {
      await createEpic(session, {
        projectId,
        title: trimmedTitle,
        description: description.trim(),
      });
      setTitle("");
      setDescription("");
      setShowComposer(false);
      toast.success("Epic created");
      refresh();
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to create task");
    } finally {
      setSending(false);
    }
  }

  return (
    <div className="flex h-full min-h-0 flex-col">
      <PageHeader
        breadcrumb={[
          { label: "Projects", to: "/projects" },
          { label: session?.projectName ?? projectId ?? "Project", to: `/projects/${projectId}/tasks` },
          { label: "Epics" },
        ]}
        title="Epics"
        subtitle={items.length > 0 ? `${items.length}${hasMore ? "+" : ""} active` : "No epics yet"}
        actions={
          <>
            <Button variant="outline" size="sm" onClick={refresh} disabled={loading || loadingMore}>
              {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : <RefreshCw className="h-4 w-4" />}
              Refresh
            </Button>
            <Button size="sm" onClick={() => setShowComposer((value) => !value)}>
              <Plus className="h-4 w-4" />
              New epic
            </Button>
          </>
        }
      />

      <div className="flex-1 overflow-y-auto p-5">
        {showComposer ? (
          <section className="panel-card mb-5 space-y-4 p-5">
            <Input
              value={title}
              onChange={(event) => setTitle(event.target.value)}
              placeholder="Epic title"
              disabled={sending}
              autoFocus
            />
            <Textarea
              value={description}
              onChange={(event) => setDescription(event.target.value)}
              placeholder="Description (optional)"
              rows={3}
              disabled={sending}
              className="resize-y rounded-xl border-white/[0.1] bg-[#111111]"
            />
            <div className="flex justify-end gap-2">
              <Button variant="ghost" size="sm" onClick={() => setShowComposer(false)}>
                Cancel
              </Button>
              <Button disabled={sending || !title.trim()} onClick={() => void submit()}>
                {sending ? <Loader2 className="h-4 w-4 animate-spin" /> : <SendHorizontal className="h-4 w-4" />}
                Create
              </Button>
            </div>
          </section>
        ) : null}

        {loading && items.length === 0 ? (
          <div className="grid gap-3 sm:grid-cols-2 xl:grid-cols-3">
            <Skeleton className="h-28 rounded-2xl" />
            <Skeleton className="h-28 rounded-2xl" />
            <Skeleton className="h-28 rounded-2xl" />
          </div>
        ) : items.length === 0 ? (
          <div className="panel-card flex flex-col items-center justify-center px-6 py-16 text-center">
            <p className="text-sm text-muted-foreground">Create your first epic to start the pipeline.</p>
            <Button className="mt-4" size="sm" onClick={() => setShowComposer(true)}>
              <Plus className="h-4 w-4" />
              New epic
            </Button>
          </div>
        ) : (
          <div className="grid gap-3 sm:grid-cols-2 xl:grid-cols-3">
            {items.map((item) => (
              <Link
                key={item.taskId}
                to={`/projects/${projectId}/tasks/${item.taskId}`}
                className="panel-card group flex min-h-[7rem] flex-col justify-between p-4 transition-colors hover:border-white/[0.14] hover:bg-[#141414]"
              >
                <div className="space-y-2">
                  <div className="flex items-center gap-2">
                    <span className={`h-2 w-2 rounded-full ${statusDot(item.status)}`} />
                    <span className="text-[11px] text-muted-foreground">#{item.taskId}</span>
                    {item.stageTitle ? (
                      <span className="rounded-md bg-white/[0.06] px-2 py-0.5 text-[10px] font-medium">
                        {item.stageTitle}
                      </span>
                    ) : null}
                  </div>
                  <p className="line-clamp-2 text-sm font-semibold text-white group-hover:text-primary">
                    {item.title || `Task #${item.taskId}`}
                  </p>
                </div>
                <div className="mt-3 flex items-center justify-between text-xs text-muted-foreground">
                  <span>{formatWhen(item.activityAt ?? item.updatedAt ?? item.createdAt)}</span>
                  <ChevronRight className="h-4 w-4 opacity-0 transition-opacity group-hover:opacity-100" />
                </div>
              </Link>
            ))}
          </div>
        )}

        <LoadMore
          loaded={items.length}
          hasMore={hasMore}
          loading={loadingMore}
          onLoadMore={() => void load(nextCursor ?? undefined, true)}
        />
      </div>
    </div>
  );
}

import { useCallback, useEffect, useRef, useState } from "react";
import { useParams } from "react-router-dom";
import { Loader2, Save } from "lucide-react";
import { toast } from "sonner";
import { StageInspectorPanel } from "@/components/workflow/StageInspectorPanel";
import { WorkflowCanvas } from "@/components/workflow/WorkflowCanvas";
import { WorkflowInspectorSidebar } from "@/components/workflow/WorkflowInspectorSidebar";
import {
  addChildTemplate,
  createStageTaskTemplate,
  createSubtaskTemplate,
  findTemplateInTree,
  moveTemplateAmongSiblings,
} from "@/components/workflow/template-graph-utils";
import {
  createEmptyStage,
  insertStageAt,
  moveStageBy,
  syncStageTemplates,
} from "@/components/workflow/workflow-utils";
import { PageHeader } from "@/components/layout/PageHeader";
import { Button } from "@/components/ui/button";
import { TeamPanel } from "@/components/workflow/TeamPanel";
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { useSession } from "@/hooks/useSession";
import { cn } from "@/lib/utils";
import {
  createMember,
  deleteMember,
  fetchProjectWorkflow,
  saveProjectWorkflow,
  updateMember,
  type ProjectMember,
  type WorkflowStage,
} from "@/lib/api";

export function WorkflowPage() {
  const { projectId = "" } = useParams();
  const session = useSession();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [dirty, setDirty] = useState(false);
  const [stages, setStages] = useState<WorkflowStage[]>([]);
  const [members, setMembers] = useState<ProjectMember[]>([]);
  const [editorIndex, setEditorIndex] = useState<number | null>(null);
  const [selectedTaskTemplateId, setSelectedTaskTemplateId] = useState<string | null>(null);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [sidebarPulse, setSidebarPulse] = useState(0);
  const [activeTab, setActiveTab] = useState("stages");
  const sidebarPulseTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const reload = useCallback(async () => {
    if (!session || !projectId) return;
    setLoading(true);
    try {
      const workflow = await fetchProjectWorkflow(session, projectId);
      setStages(workflow.stages);
      setMembers(workflow.members);
      setDirty(false);
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to load workflow");
    } finally {
      setLoading(false);
    }
  }, [session, projectId]);

  useEffect(() => {
    void reload();
  }, [reload]);

  useEffect(() => {
    return () => {
      if (sidebarPulseTimerRef.current) clearTimeout(sidebarPulseTimerRef.current);
    };
  }, []);

  useEffect(() => {
    if (activeTab !== "stages") {
      setSidebarOpen(false);
    }
  }, [activeTab]);

  function revealSidebar() {
    if (sidebarPulseTimerRef.current) clearTimeout(sidebarPulseTimerRef.current);
    setSidebarOpen(false);
    sidebarPulseTimerRef.current = setTimeout(() => {
      setSidebarOpen(true);
      setSidebarPulse((value) => value + 1);
      sidebarPulseTimerRef.current = null;
    }, 130);
  }

  function markDirty(next: WorkflowStage[]) {
    setStages([...next].sort((a, b) => a.position - b.position));
    setDirty(true);
  }

  function selectNewStage(next: WorkflowStage[], index: number, taskTemplateId: string | null = null) {
    markDirty(next);
    setEditorIndex(index);
    setSelectedTaskTemplateId(taskTemplateId);
    revealSidebar();
  }

  function addStageAtEnd() {
    const next = [...stages, createEmptyStage(stages.length)];
    selectNewStage(next, next.length - 1);
  }

  function insertStageAfter(afterIndex: number) {
    const stage = createEmptyStage(afterIndex + 1);
    const next = insertStageAt(stages, afterIndex, stage);
    selectNewStage(next, afterIndex + 1);
  }

  function moveStage(index: number, delta: -1 | 1) {
    const next = moveStageBy(stages, index, delta);
    if (next === stages) return;
    markDirty(next);
    const target = index + delta;
    setEditorIndex(target);
  }

  async function handleSaveStages() {
    if (!session) return;
    setSaving(true);
    try {
      const workflow = await saveProjectWorkflow(session, projectId, { stages, roles: [] });
      setStages(workflow.stages);
      setDirty(false);
      toast.success("Workflow saved");
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to save workflow");
    } finally {
      setSaving(false);
    }
  }

  function updateStageAt(index: number, stage: WorkflowStage) {
    markDirty(stages.map((item, idx) => (idx === index ? syncStageTemplates(stage) : item)));
  }

  function removeStageAt(index: number) {
    if (stages.length <= 1) {
      toast.error("At least one pipeline step is required");
      return;
    }
    const stage = stages[index];
    const activeTasks = stage?.activeTaskCount ?? 0;
    if (activeTasks > 0) {
      toast.error(`${activeTasks} epic(s) are on this step and it cannot be deleted`);
      return;
    }
    markDirty(
      stages.filter((_, idx) => idx !== index).map((stage, position) => ({ ...stage, position })),
    );
    setEditorIndex(null);
    setSelectedTaskTemplateId(null);
    setSidebarOpen(false);
  }

  async function handleCreateMember(input: { name: string; role: string; actorKind: ProjectMember["actorKind"] }) {
    if (!session) return;
    const member = await createMember(session, projectId, input);
    setMembers((current) => [...current, member].sort((a, b) => a.name.localeCompare(b.name)));
    toast.success("Member added");
  }

  const editingStage = editorIndex !== null ? stages[editorIndex] ?? null : null;

  function setStageBySortedIndex(sortedIndex: number | null, taskTemplateId: string | null = null) {
    if (sortedIndex === null) {
      setEditorIndex(null);
      setSelectedTaskTemplateId(null);
      return;
    }
    const sorted = [...stages].sort((a, b) => a.position - b.position);
    const stage = sorted[sortedIndex];
    if (!stage) return;
    const index = stages.findIndex((item) => item.id === stage.id);
    setEditorIndex(index >= 0 ? index : null);
    setSelectedTaskTemplateId(taskTemplateId);
  }

  function selectFromCanvas(sortedIndex: number, taskTemplateId: string | null = null) {
    setStageBySortedIndex(sortedIndex, taskTemplateId);
    revealSidebar();
  }

  function closeInspector() {
    setEditorIndex(null);
    setSelectedTaskTemplateId(null);
    setSidebarOpen(false);
  }

  function stageAtSortedIndex(sortedIndex: number) {
    const sorted = [...stages].sort((a, b) => a.position - b.position);
    const stage = sorted[sortedIndex];
    if (!stage) return null;
    const index = stages.findIndex((item) => item.id === stage.id);
    if (index < 0) return null;
    return { stage, index };
  }

  function addStageTask(sortedIndex: number) {
    const entry = stageAtSortedIndex(sortedIndex);
    if (!entry) return;
    const templates = entry.stage.taskTemplates ?? [];
    const created = createStageTaskTemplate(entry.stage.title, templates.length);
    const next = stages.map((item, idx) =>
      idx === entry.index
        ? syncStageTemplates({ ...item, taskTemplates: [...templates, created] })
        : item,
    );
    selectNewStage(next, entry.index, created.id);
  }

  function moveTaskTemplate(sortedIndex: number, templateId: string, delta: -1 | 1) {
    const entry = stageAtSortedIndex(sortedIndex);
    if (!entry) return;
    const templates = entry.stage.taskTemplates ?? [];
    const next = stages.map((item, idx) =>
      idx === entry.index
        ? syncStageTemplates({
            ...item,
            taskTemplates: moveTemplateAmongSiblings(templates, templateId, delta),
          })
        : item,
    );
    markDirty(next);
  }

  function addSubtask(sortedIndex: number, parentTemplateId: string) {
    const entry = stageAtSortedIndex(sortedIndex);
    if (!entry) return;
    const templates = entry.stage.taskTemplates ?? [];
    const parent = findTemplateInTree(templates, parentTemplateId);
    if (!parent) return;
    const created = createSubtaskTemplate(
      parent.template.title,
      parent.template.children?.length ?? 0,
    );
    const next = stages.map((item, idx) =>
      idx === entry.index
        ? syncStageTemplates({
            ...item,
            taskTemplates: addChildTemplate(templates, parentTemplateId, created),
          })
        : item,
    );
    selectNewStage(next, entry.index, created.id);
  }

  if (!session) return null;

  if (loading) {
    return (
      <div className="flex justify-center py-20">
        <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
      </div>
    );
  }

  return (
    <div className="flex h-full min-h-0 flex-col overflow-hidden">
      <PageHeader
        breadcrumb={[
          { label: "Projects", to: "/projects" },
          { label: session?.projectName ?? projectId ?? "Project", to: `/projects/${projectId}/tasks` },
          { label: "Pipeline" },
        ]}
        title="Pipeline"
        subtitle="Pipeline steps and task templates ┬╖ epics run this workflow"
        actions={
          <>
            {dirty ? (
              <span className="rounded-full border border-warn/30 bg-warn/10 px-2.5 py-1 text-xs font-medium text-warn">
                Unsaved changes
              </span>
            ) : null}
            <Button onClick={() => void handleSaveStages()} disabled={saving || !dirty}>
              {saving ? <Loader2 className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
              Save workflow
            </Button>
          </>
        }
      />

      <Tabs value={activeTab} onValueChange={setActiveTab} className="flex min-h-0 flex-1 flex-col">
        <div className="shrink-0 border-b border-white/[0.06] px-5">
          <TabsList className="h-10 bg-transparent p-0">
            <TabsTrigger value="stages" className="rounded-none border-b-2 border-transparent data-[state=active]:border-primary data-[state=active]:bg-transparent">
              Pipeline
            </TabsTrigger>
            <TabsTrigger value="members" className="rounded-none border-b-2 border-transparent data-[state=active]:border-primary data-[state=active]:bg-transparent">
              Team
            </TabsTrigger>
          </TabsList>
        </div>

        <div className={cn("flex min-h-0 flex-1", activeTab !== "stages" && "hidden")}>
          <WorkflowCanvas
              className="min-h-0 flex-1"
              stages={stages}
              selectedStageId={editingStage?.id ?? null}
              selectedTaskTemplateId={selectedTaskTemplateId}
              onAddStage={addStageAtEnd}
              onInsertStageAfter={insertStageAfter}
              onMoveStage={moveStage}
              onSelectStage={(flowIndex) => selectFromCanvas(flowIndex, null)}
              onSelectTaskTemplate={(flowIndex, templateId) => selectFromCanvas(flowIndex, templateId)}
              onAddStageTask={(flowIndex) => addStageTask(flowIndex)}
              onAddSubtask={(flowIndex, parentId) => addSubtask(flowIndex, parentId)}
              onMoveTaskTemplate={(flowIndex, templateId, delta) =>
                moveTaskTemplate(flowIndex, templateId, delta)
              }
            />
            <WorkflowInspectorSidebar
              open={sidebarOpen && (editingStage !== null || selectedTaskTemplateId !== null)}
              pulseKey={sidebarPulse}
              onOpenChange={(next) => {
                if (!next) closeInspector();
                else if (editingStage) setSidebarOpen(true);
              }}
            >
              {editingStage ? (
                <StageInspectorPanel
                  stage={editingStage}
                  stageCount={stages.length}
                  selectedTaskTemplateId={selectedTaskTemplateId}
                  onChange={(stage) => {
                    if (editorIndex === null) return;
                    updateStageAt(editorIndex, stage);
                  }}
                  onSelectTaskTemplate={setSelectedTaskTemplateId}
                  onDeleteStage={() => {
                    if (editorIndex === null) return;
                    removeStageAt(editorIndex);
                  }}
                  onClose={closeInspector}
                />
              ) : null}
            </WorkflowInspectorSidebar>
        </div>
        <div className={cn("min-h-0 flex-1 overflow-y-auto", activeTab !== "members" && "hidden")}>
          <TeamPanel
              members={members}
              onCreateMember={async (input) => {
                try {
                  await handleCreateMember(input);
                } catch (error) {
                  toast.error(error instanceof Error ? error.message : "Failed to add member");
                }
              }}
              onUpdateMember={async (memberId, patch) => {
                if (!session) return;
                try {
                  const updated = await updateMember(session, projectId, memberId, patch);
                  setMembers((current) => current.map((item) => (item.id === memberId ? updated : item)));
                } catch (error) {
                  toast.error(error instanceof Error ? error.message : "Failed to update member");
                }
              }}
              onDeleteMember={async (id, name) => {
                if (!session) return;
                try {
                  await deleteMember(session, projectId, id);
                  setMembers((current) => current.filter((item) => item.id !== id));
                  toast.success(`Deleted "${name}"`);
                } catch (error) {
                  toast.error(error instanceof Error ? error.message : "Failed to delete member");
                }
              }}
            />
        </div>
      </Tabs>
    </div>
  );
}

import { useCallback, useEffect, useRef, useState } from "react";
import { Download, Loader2, Plus, Save, Trash2, Upload } from "lucide-react";
import { toast } from "sonner";
import { PageHeader } from "@/components/layout/PageHeader";
import { StageInspectorPanel } from "@/components/workflow/StageInspectorPanel";
import { WorkflowCanvas } from "@/components/workflow/WorkflowCanvas";
import {
  addChildTemplate,
  createStageTaskTemplate,
  createSubtaskTemplate,
  findTemplateInTree,
  moveTemplateAmongSiblings,
} from "@/components/workflow/template-graph-utils";
import {
  createEmptyStage,
  insertStageAt,
  moveStageBy,
  syncStageTemplates,
} from "@/components/workflow/workflow-utils";
import { Button } from "@/components/ui/button";
import { useSession } from "@/hooks/useSession";
import type { WorkflowTemplate } from "@/lib/api";
import {
  createWorkflowTemplate,
  deleteWorkflowTemplate,
  exportWorkflowTemplate,
  fetchWorkflowTemplate,
  fetchWorkflowTemplates,
  importWorkflowTemplate,
  PROTECTED_WORKFLOW_TEMPLATE_IDS,
  saveWorkflowTemplate,
  type WorkflowStage,
  type WorkflowTemplateSummary,
} from "@/lib/api";
import { useConfirm } from "@/lib/confirm";
import { cn } from "@/lib/utils";

export function WorkflowTemplatesPage() {
  const session = useSession();
  const { confirmDestructive } = useConfirm();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [deleting, setDeleting] = useState(false);
  const [dirty, setDirty] = useState(false);
  const [templates, setTemplates] = useState<WorkflowTemplateSummary[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [stages, setStages] = useState<WorkflowStage[]>([]);
  const [editorIndex, setEditorIndex] = useState<number | null>(null);
  const [selectedTaskTemplateId, setSelectedTaskTemplateId] = useState<string | null>(null);
  const [newTemplateTitle, setNewTemplateTitle] = useState("");
  const [creatingTemplate, setCreatingTemplate] = useState(false);
  const [importing, setImporting] = useState(false);
  const importInputRef = useRef<HTMLInputElement>(null);

  const loadTemplates = useCallback(async () => {
    if (!session) return;
    const items = await fetchWorkflowTemplates(session);
    setTemplates(items);
    if (items.length > 0 && !selectedId) {
      setSelectedId(items[0]?.id ?? null);
    }
  }, [session, selectedId]);

  const loadTemplateStages = useCallback(async () => {
    if (!session || !selectedId) return;
    setLoading(true);
    try {
      const template = await fetchWorkflowTemplate(session, selectedId);
      setStages(template.stages);
      setDirty(false);
      setEditorIndex(null);
      setSelectedTaskTemplateId(null);
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to load template");
    } finally {
      setLoading(false);
    }
  }, [session, selectedId]);

  useEffect(() => {
    void loadTemplates().catch((error) => {
      toast.error(error instanceof Error ? error.message : "Failed to load templates");
    });
  }, [loadTemplates]);

  useEffect(() => {
    if (selectedId) {
      void loadTemplateStages();
    }
  }, [loadTemplateStages, selectedId]);

  function markDirty(next: WorkflowStage[]) {
    setStages([...next].sort((a, b) => a.position - b.position));
    setDirty(true);
  }

  function selectNewStage(next: WorkflowStage[], index: number, taskTemplateId: string | null = null) {
    markDirty(next);
    setEditorIndex(index);
    setSelectedTaskTemplateId(taskTemplateId);
  }

  function addStageAtEnd() {
    const next = [...stages, createEmptyStage(stages.length)];
    selectNewStage(next, next.length - 1);
  }

  function insertStageAfter(afterIndex: number) {
    const stage = createEmptyStage(afterIndex + 1);
    const next = insertStageAt(stages, afterIndex, stage);
    selectNewStage(next, afterIndex + 1);
  }

  function moveStage(index: number, delta: -1 | 1) {
    const next = moveStageBy(stages, index, delta);
    if (next === stages) return;
    markDirty(next);
    setEditorIndex(index + delta);
  }

  async function handleCreateTemplate() {
    if (!session || !newTemplateTitle.trim()) return;
    if (dirty && !window.confirm("You have unsaved changes. Continue anyway?")) return;
    setCreatingTemplate(true);
    try {
      const template = await createWorkflowTemplate(session, { title: newTemplateTitle.trim() });
      setTemplates((current) =>
        [...current, { id: template.id, title: template.title, description: template.description }].sort((a, b) =>
          a.title.localeCompare(b.title),
        ),
      );
      setSelectedId(template.id);
      setStages(template.stages);
      setDirty(false);
      setEditorIndex(null);
      setSelectedTaskTemplateId(null);
      setNewTemplateTitle("");
      toast.success("Template created");
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to create template");
    } finally {
      setCreatingTemplate(false);
    }
  }

  async function handleExport() {
    if (!session || !selectedId) return;
    try {
      await exportWorkflowTemplate(session, selectedId);
    } catch {
      toast.error("Export failed");
    }
  }

  async function handleImportFile(file: File) {
    if (!session) return;
    setImporting(true);
    try {
      const text = await file.text();
      const data = JSON.parse(text) as WorkflowTemplate;
      const template = await importWorkflowTemplate(session, data);
      setTemplates((current) =>
        [...current, { id: template.id, title: template.title, description: template.description }].sort(
          (a, b) => a.title.localeCompare(b.title),
        ),
      );
      setSelectedId(template.id);
      setStages(template.stages);
      setDirty(false);
      setEditorIndex(null);
      setSelectedTaskTemplateId(null);
      toast.success(`Imported "${template.title}"`);
    } catch (err) {
      toast.error(err instanceof Error ? err.message : "Import failed ΓÇö check file format");
    } finally {
      setImporting(false);
      if (importInputRef.current) importInputRef.current.value = "";
    }
  }

  async function handleDeleteTemplate(template: WorkflowTemplateSummary) {
    if (!session || PROTECTED_WORKFLOW_TEMPLATE_IDS.has(template.id)) return;
    if (!(await confirmDestructive(`Delete template "${template.title}"? This cannot be undone.`))) {
      return;
    }
    setDeleting(true);
    try {
      await deleteWorkflowTemplate(session, template.id);
      const remaining = templates.filter((item) => item.id !== template.id);
      setTemplates(remaining);
      if (selectedId === template.id) {
        setSelectedId(remaining[0]?.id ?? null);
        setStages([]);
        setDirty(false);
        setEditorIndex(null);
        setSelectedTaskTemplateId(null);
      }
      toast.success(`Deleted "${template.title}"`);
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to delete template");
    } finally {
      setDeleting(false);
    }
  }

  const selectedTemplate = templates.find((item) => item.id === selectedId) ?? null;
  const canDeleteSelected =
    selectedTemplate !== null && !PROTECTED_WORKFLOW_TEMPLATE_IDS.has(selectedTemplate.id);

  async function handleSave() {
    if (!session || !selectedId) return;
    setSaving(true);
    try {
      const template = await saveWorkflowTemplate(session, selectedId, stages);
      setStages(template.stages);
      setDirty(false);
      toast.success("Template saved");
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Failed to save template");
    } finally {
      setSaving(false);
    }
  }

  const editingStage = editorIndex !== null ? stages[editorIndex] ?? null : null;

  function setStageBySortedIndex(sortedIndex: number | null, taskTemplateId: string | null = null) {
    if (sortedIndex === null) {
      setEditorIndex(null);
      setSelectedTaskTemplateId(null);
      return;
    }
    const sorted = [...stages].sort((a, b) => a.position - b.position);
    const stage = sorted[sortedIndex];
    if (!stage) return;
    const index = stages.findIndex((item) => item.id === stage.id);
    setEditorIndex(index >= 0 ? index : null);
    setSelectedTaskTemplateId(taskTemplateId);
  }

  function stageAtSortedIndex(sortedIndex: number) {
    const sorted = [...stages].sort((a, b) => a.position - b.position);
    const stage = sorted[sortedIndex];
    if (!stage) return null;
    const index = stages.findIndex((item) => item.id === stage.id);
    if (index < 0) return null;
    return { stage, index };
  }

  function addStageTask(sortedIndex: number) {
    const entry = stageAtSortedIndex(sortedIndex);
    if (!entry) return;
    const templates = entry.stage.taskTemplates ?? [];
    const created = createStageTaskTemplate(entry.stage.title, templates.length);
    const next = stages.map((item, idx) =>
      idx === entry.index
        ? syncStageTemplates({ ...item, taskTemplates: [...templates, created] })
        : item,
    );
    selectNewStage(next, entry.index, created.id);
  }

  function moveTaskTemplate(sortedIndex: number, templateId: string, delta: -1 | 1) {
    const entry = stageAtSortedIndex(sortedIndex);
    if (!entry) return;
    const templates = entry.stage.taskTemplates ?? [];
    const next = stages.map((item, idx) =>
      idx === entry.index
        ? syncStageTemplates({
            ...item,
            taskTemplates: moveTemplateAmongSiblings(templates, templateId, delta),
          })
        : item,
    );
    markDirty(next);
  }

  function addSubtask(sortedIndex: number, parentTemplateId: string) {
    const entry = stageAtSortedIndex(sortedIndex);
    if (!entry) return;
    const templates = entry.stage.taskTemplates ?? [];
    const parent = findTemplateInTree(templates, parentTemplateId);
    if (!parent) return;
    const created = createSubtaskTemplate(
      parent.template.title,
      parent.template.children?.length ?? 0,
    );
    const next = stages.map((item, idx) =>
      idx === entry.index
        ? syncStageTemplates({
            ...item,
            taskTemplates: addChildTemplate(templates, parentTemplateId, created),
          })
        : item,
    );
    selectNewStage(next, entry.index, created.id);
  }

  if (!session) return null;

  return (
    <div className="flex h-full min-h-0 overflow-hidden">
      <aside className="flex w-[240px] shrink-0 flex-col border-r border-white/[0.07] bg-black">
        <div className="space-y-2 border-b border-white/[0.06] px-3 py-3">
          <p className="px-1 text-[10px] font-medium uppercase tracking-wider text-muted-foreground">Templates</p>
          <div className="flex h-9 w-full overflow-hidden rounded-lg border border-white/[0.1] bg-[#111111] shadow-sm ring-offset-black focus-within:ring-2 focus-within:ring-ring focus-within:ring-offset-2 focus-within:ring-offset-black">
            <input
              value={newTemplateTitle}
              onChange={(event) => setNewTemplateTitle(event.target.value)}
              placeholder="New template"
              disabled={creatingTemplate}
              className="min-w-0 flex-1 border-0 bg-transparent px-3 text-sm text-foreground placeholder:text-muted-foreground focus-visible:outline-none disabled:cursor-not-allowed disabled:opacity-50"
              onKeyDown={(event) => {
                if (event.key === "Enter" && newTemplateTitle.trim()) {
                  event.preventDefault();
                  void handleCreateTemplate();
                }
              }}
            />
            <Button
              type="button"
              variant="ghost"
              size="icon"
              className="h-full w-9 shrink-0 rounded-none border-l border-white/[0.1] hover:bg-white/[0.06]"
              disabled={!newTemplateTitle.trim() || creatingTemplate}
              onClick={() => void handleCreateTemplate()}
            >
              {creatingTemplate ? <Loader2 className="h-4 w-4 animate-spin" /> : <Plus className="h-4 w-4" />}
            </Button>
          </div>
          {/* Import from JSON file */}
          <input
            ref={importInputRef}
            type="file"
            accept=".json,application/json"
            className="hidden"
            onChange={(e) => {
              const file = e.target.files?.[0];
              if (file) void handleImportFile(file);
            }}
          />
          <Button
            type="button"
            variant="outline"
            size="sm"
            className="h-9 w-full"
            disabled={importing}
            onClick={() => importInputRef.current?.click()}
          >
            {importing ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <Upload className="h-3.5 w-3.5" />}
            Import JSON
          </Button>
        </div>

        <div className="flex-1 space-y-0.5 overflow-y-auto p-2">
          {templates.map((template) => (
            <div key={template.id} className="group relative">
              <button
                type="button"
                onClick={() => {
                  if (dirty && !window.confirm("Discard unsaved changes?")) return;
                  setSelectedId(template.id);
                }}
                className={cn(
                  "w-full rounded-lg px-3 py-2.5 pr-16 text-left transition-colors",
                  selectedId === template.id
                    ? "bg-white/[0.08] text-foreground"
                    : "text-muted-foreground hover:bg-white/[0.04] hover:text-foreground",
                )}
              >
                <p className="text-sm font-medium">{template.title}</p>
                <p className="mt-0.5 truncate text-xs text-muted-foreground">{template.description}</p>
              </button>
              {/* Export button ΓÇö visible on hover or when selected */}
              <div className="absolute right-2 top-1/2 flex -translate-y-1/2 items-center gap-0.5">
                <button
                  type="button"
                  title="Export as JSON"
                  onClick={(e) => {
                    e.stopPropagation();
                    setSelectedId(template.id);
                    void exportWorkflowTemplate(session, template.id).catch(() =>
                      toast.error("Export failed"),
                    );
                  }}
                  className={cn(
                    "rounded p-1 transition-opacity",
                    "text-muted-foreground hover:text-foreground",
                    selectedId === template.id
                      ? "opacity-100"
                      : "opacity-0 group-hover:opacity-100",
                  )}
                >
                  <Download className="h-3.5 w-3.5" />
                </button>
                {!PROTECTED_WORKFLOW_TEMPLATE_IDS.has(template.id) ? (
                  <button
                    type="button"
                    title="Delete template"
                    disabled={deleting}
                    onClick={(e) => {
                      e.stopPropagation();
                      void handleDeleteTemplate(template);
                    }}
                    className={cn(
                      "rounded p-1 transition-opacity",
                      "text-muted-foreground hover:text-destructive",
                      selectedId === template.id
                        ? "opacity-100"
                        : "opacity-0 group-hover:opacity-100",
                    )}
                  >
                    <Trash2 className="h-3.5 w-3.5" />
                  </button>
                ) : null}
              </div>
            </div>
          ))}
        </div>

      </aside>

      <div className="flex min-h-0 flex-1 flex-col">
        <PageHeader
          title={selectedTemplate?.title ?? "Template"}
          subtitle="Stages and task templates"
          actions={
            <>
              {dirty ? (
                <span className="rounded-full border border-warn/30 bg-warn/10 px-2.5 py-1 text-xs font-medium text-warn">
                  Unsaved
                </span>
              ) : null}
              {selectedId ? (
                <Button variant="outline" onClick={() => void handleExport()}>
                  <Download className="h-4 w-4" />
                  Export
                </Button>
              ) : null}
              {canDeleteSelected && selectedTemplate ? (
                <Button
                  variant="outline"
                  className="text-destructive hover:text-destructive"
                  disabled={deleting}
                  onClick={() => void handleDeleteTemplate(selectedTemplate)}
                >
                  {deleting ? <Loader2 className="h-4 w-4 animate-spin" /> : <Trash2 className="h-4 w-4" />}
                  Delete
                </Button>
              ) : null}
              <Button onClick={() => void handleSave()} disabled={saving || !dirty || !selectedId}>
                {saving ? <Loader2 className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
                Save
              </Button>
            </>
          }
        />

        {loading ? (
          <div className="flex flex-1 items-center justify-center">
            <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
          </div>
        ) : (
          <div className="flex min-h-0 flex-1">
            <WorkflowCanvas
              className="min-h-0 flex-1"
              stages={stages}
              selectedStageId={editingStage?.id ?? null}
              selectedTaskTemplateId={selectedTaskTemplateId}
              onAddStage={addStageAtEnd}
              onInsertStageAfter={insertStageAfter}
              onMoveStage={moveStage}
              onSelectStage={(flowIndex) => setStageBySortedIndex(flowIndex, null)}
              onSelectTaskTemplate={(flowIndex, templateId) => setStageBySortedIndex(flowIndex, templateId)}
              onAddStageTask={(flowIndex) => addStageTask(flowIndex)}
              onAddSubtask={(flowIndex, parentId) => addSubtask(flowIndex, parentId)}
              onMoveTaskTemplate={(flowIndex, templateId, delta) =>
                moveTaskTemplate(flowIndex, templateId, delta)
              }
            />
            <aside className="flex w-[380px] shrink-0 flex-col border-l border-white/[0.07] bg-[#0a0a0a]">
              <div className="flex-1 overflow-y-auto p-4">
            {editingStage ? (
              <StageInspectorPanel
                stage={editingStage}
                stageCount={stages.length}
                selectedTaskTemplateId={selectedTaskTemplateId}
                onChange={(stage) => {
                  if (editorIndex === null) return;
                  markDirty(stages.map((item, idx) => (idx === editorIndex ? syncStageTemplates(stage) : item)));
                }}
                onSelectTaskTemplate={setSelectedTaskTemplateId}
                onDeleteStage={() => {
                  if (editorIndex === null) return;
                  if (stages.length <= 1) {
                    toast.error("At least one stage is required");
                    return;
                  }
                  markDirty(
                    stages.filter((_, idx) => idx !== editorIndex).map((stage, position) => ({ ...stage, position })),
                  );
                  setEditorIndex(null);
                  setSelectedTaskTemplateId(null);
                }}
                onClose={() => {
                  setEditorIndex(null);
                  setSelectedTaskTemplateId(null);
                }}
              />
            ) : null}
              </div>
            </aside>
          </div>
        )}
      </div>
    </div>
  );
}
